(** n = 5 per-class 2-realizer lemmas and helpers.

    Split out from RemovablePairs.v.  Closes the ~82 isomorphism
    classes for posets on a carrier of cardinality 5 that are neither
    antichains nor chains.  The residual catch-all
    [n5_residual_classes_two_realizer] (a focused Admitted TODO) and
    the dispatcher [n5_nonantichain_nonchain_two_realizer] live in
    N5Dispatcher.v so that this file (which holds the bulk of the
    per-class Qed proofs) can be compiled independently of the
    cascade. *)

From Stdlib Require Import List Classical Arith Lia.
From Stdlib Require Import FunctionalExtensionality PropExtensionality ProofIrrelevance.
From Stdlib Require Import IndefiniteDescription ClassicalDescription.
From Stdlib Require Import Relations.Relation_Operators.
From Posets Require Import PosetClasses.
From Dimension Require Import DimDefs CriticalPairs Szpilrajn Theorems.
From ZornsLemma Require Import FiniteTypes EnsemblesExplicit.
From Stdlib Require Import Ensembles Finite_sets Finite_sets_facts.

(** ** Tactics for the n=5 dispatcher cascade

    The dispatcher cascade discharges ~80 isomorphism classes for
    posets on a 5-element carrier.  Most cascade branches close
    [Hno_fourth] sub-goals by witnessing some upstream [Hn<class>]
    hypothesis with the five carrier elements [p, q, r, s, t].  The
    witnessing pattern is mechanical:

      - 10 [a <> b] distinctness obligations (either available
        directly or via [symmetry]).
      - A handful of [R2 a b] edge obligations (available locally).
      - One [forall u v, R2 u v -> u = v \/ ...] closure obligation,
        which is dispatched by classical case-analysis on whether
        [(u, v)] matches each named edge, then falling through to
        [Hno_fourth]. *)

(** Discharge a distinctness obligation [a <> b] using whichever
    direction is in context.  Falls back to plain [assumption]. *)
Ltac n5_neq_assumption :=
  first
    [ assumption
    | (let Heq := fresh "Heq" in
       intro Heq; symmetry in Heq; revert Heq; assumption)
    ].

(** Solve the head of an [exists a b c d e, ...] obligation built from
    a chain of [/\] conjuncts of distinctness, edges, and a trailing
    [forall] closure.  The user supplies the 5 witnesses; [repeat split]
    fans out the conjuncts and [n5_neq_assumption] discharges
    distinctness sub-goals while plain [assumption] handles edges. *)
Ltac n5_split_witness w1 w2 w3 w4 w5 :=
  exists w1, w2, w3, w4, w5;
  repeat (split; [ first [ n5_neq_assumption | assumption ] |]);
  first [ n5_neq_assumption | assumption | idtac ].

(** Close the trailing [forall u v, R2 u v -> u = v \/ branches...]
    obligation of a [Hn<class>] witness, where [branches] is a
    disjunction of [(u = a_i /\ v = b_i)] clauses.  At each step,
    classically decide whether [(u, v)] matches the current edge; if
    so, prove that branch; otherwise descend into the right disjunct.
    Once all named edges are exhausted, fall through to [Hno_fourth]
    (or analogously named "no further edge" hypothesis), which asserts
    no extra edge exists. *)
Ltac n5_close_forall_step :=
  match goal with
  | [ |- _ \/ _ ] =>
      let Heq := fresh "Heq" in
      let Hne := fresh "Hne" in
      first
        [ left; split; reflexivity
        | right; n5_close_forall_step
        | (* Fall-through: caller's responsibility. *) idtac ]
  end.

Ltac n5_close_forall_via Hno_fourth :=
  let u := fresh "u" in
  let v := fresh "v" in
  let HRuv := fresh "HRuv" in
  let Heq := fresh "Heq" in
  let Huv_neq := fresh "Huv_neq" in
  intros u v HRuv;
  destruct (classic (u = v)) as [Heq | Huv_neq];
    [left; exact Heq |];
  right;
  (* Recursively decide each named-edge case. *)
  repeat
    (match goal with
     | [ |- (u = ?a /\ v = ?b) \/ _ ] =>
         let Hcase := fresh "Hcase" in
         let Hnot := fresh "Hnot" in
         destruct (classic (u = a /\ v = b)) as [Hcase | Hnot];
         [ left; exact Hcase | right ]
     | [ |- u = ?a /\ v = ?b ] =>
         let Hcase := fresh "Hcase" in
         let Hnot := fresh "Hnot" in
         destruct (classic (u = a /\ v = b)) as [Hcase | Hnot];
         [ exact Hcase | ]
     end);
  (* Fall-through: contradict Hno_fourth using HRuv and the accumulated
     Hnot* hypotheses. *)
  exfalso; apply Hno_fourth;
  exists u, v;
  repeat (split; [ first [ exact Huv_neq | exact HRuv | assumption ] |]);
  first [ exact Huv_neq | exact HRuv | assumption ].

(** Helper for [n5_one_edge_two_realizer]: when [Full_set B] has
    cardinal 5, extract 5 pairwise distinct elements and confirm that
    every element of [B] equals one of them.  Follows the same pattern
    as [carrier_4_destructure] with one extra [cardinal_subtract_sn]
    step. *)
Lemma carrier_5_destructure :
  forall {B : Type} (p q : B),
  cardinal B (Full_set B) 5 ->
  p <> q ->
  exists r s t : B,
    p <> r /\ p <> s /\ p <> t /\
    q <> r /\ q <> s /\ q <> t /\
    r <> s /\ r <> t /\ s <> t /\
    (forall a : B, a = p \/ a = q \/ a = r \/ a = s \/ a = t).
Proof.
  intros B p q Hcard Hpq.
  (* Strip p. *)
  assert (Hp_in : In B (Full_set B) p) by apply Full_intro.
  assert (Hcard1 : cardinal B (Subtract B (Full_set B) p) 4)
    by exact (cardinal_subtract_sn B (Full_set B) p 4 Hcard Hp_in).
  (* Strip q. *)
  assert (Hq_in1 : In B (Subtract B (Full_set B) p) q).
  { apply Subtract_intro; [apply Full_intro |]. exact Hpq. }
  assert (Hcard2 : cardinal B (Subtract B (Subtract B (Full_set B) p) q) 3)
    by exact (cardinal_subtract_sn B (Subtract B (Full_set B) p) q 3 Hcard1 Hq_in1).
  (* Pick r. *)
  assert (Hinh2 : Inhabited B (Subtract B (Subtract B (Full_set B) p) q))
    by exact (cardinal_elim B _ 3 Hcard2).
  destruct Hinh2 as [r Hr_in2].
  destruct (Subtract_inv _ _ _ _ Hr_in2) as [Hr_in1 Hqr_neq].
  destruct (Subtract_inv _ _ _ _ Hr_in1) as [_ Hpr_neq].
  (* Strip r. *)
  assert (Hcard3 : cardinal B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) 2)
    by exact (cardinal_subtract_sn B _ r 2 Hcard2 Hr_in2).
  (* Pick s. *)
  assert (Hinh3 : Inhabited B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r))
    by exact (cardinal_elim B _ 2 Hcard3).
  destruct Hinh3 as [s Hs_in3].
  destruct (Subtract_inv _ _ _ _ Hs_in3) as [Hs_in2 Hrs_neq].
  destruct (Subtract_inv _ _ _ _ Hs_in2) as [Hs_in1 Hqs_neq].
  destruct (Subtract_inv _ _ _ _ Hs_in1) as [_ Hps_neq].
  (* Strip s. *)
  assert (Hcard4 : cardinal B (Subtract B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) s) 1)
    by exact (cardinal_subtract_sn B _ s 1 Hcard3 Hs_in3).
  (* Pick t. *)
  assert (Hinh4 : Inhabited B (Subtract B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) s))
    by exact (cardinal_elim B _ 1 Hcard4).
  destruct Hinh4 as [t Ht_in4].
  destruct (Subtract_inv _ _ _ _ Ht_in4) as [Ht_in3 Hst_neq].
  destruct (Subtract_inv _ _ _ _ Ht_in3) as [Ht_in2 Hrt_neq].
  destruct (Subtract_inv _ _ _ _ Ht_in2) as [Ht_in1 Hqt_neq].
  destruct (Subtract_inv _ _ _ _ Ht_in1) as [_ Hpt_neq].
  (* Strip t: residual is empty. *)
  assert (Hcard5 : cardinal B (Subtract B (Subtract B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) s) t) 0)
    by exact (cardinal_subtract_sn B _ t 0 Hcard4 Ht_in4).
  assert (Hempty : Subtract B (Subtract B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) s) t = Empty_set B)
    by exact (cardinal_elim B _ 0 Hcard5).
  exists r, s, t.
  split; [exact Hpr_neq |].
  split; [exact Hps_neq |].
  split; [exact Hpt_neq |].
  split; [exact Hqr_neq |].
  split; [exact Hqs_neq |].
  split; [exact Hqt_neq |].
  split; [exact Hrs_neq |].
  split; [exact Hrt_neq |].
  split; [exact Hst_neq |].
  intro a.
  destruct (excluded_middle_informative (a = p)) as [Hap | Hnap]; [auto |].
  destruct (excluded_middle_informative (a = q)) as [Haq | Hnaq]; [auto |].
  destruct (excluded_middle_informative (a = r)) as [Har | Hnar]; [auto |].
  destruct (excluded_middle_informative (a = s)) as [Has | Hnas]; [auto |].
  destruct (excluded_middle_informative (a = t)) as [Hat | Hnat]; [auto |].
  exfalso.
  assert (Hin_full : In B (Full_set B) a) by apply Full_intro.
  assert (Hin1 : In B (Subtract B (Full_set B) p) a)
    by exact (Subtract_intro _ _ _ _ Hin_full (fun He => Hnap (eq_sym He))).
  assert (Hin2 : In B (Subtract B (Subtract B (Full_set B) p) q) a)
    by exact (Subtract_intro _ _ _ _ Hin1 (fun He => Hnaq (eq_sym He))).
  assert (Hin3 : In B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) a)
    by exact (Subtract_intro _ _ _ _ Hin2 (fun He => Hnar (eq_sym He))).
  assert (Hin4 : In B (Subtract B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) s) a)
    by exact (Subtract_intro _ _ _ _ Hin3 (fun He => Hnas (eq_sym He))).
  assert (Hin5 : In B (Subtract B (Subtract B (Subtract B (Subtract B (Subtract B (Full_set B) p) q) r) s) t) a)
    by exact (Subtract_intro _ _ _ _ Hin4 (fun He => Hnat (eq_sym He))).
  rewrite Hempty in Hin5.
  destruct Hin5.
Qed.

(** Helper: a 5-element carrier on which every pair is R2-comparable
    cannot host an incomparable pair.  Used to discharge residual
    sub-cases where transitive closure forces a 5-chain (total order),
    contradicting the existence of an incomparable pair. *)
Lemma n5_chain_contra_inc :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2}
    (p q r s t : B)
    (Hcov5 : forall a : B, a = p \/ a = q \/ a = r \/ a = s \/ a = t)
    (Hinc_ex : exists a b : B, @Incomparable B R2 a b)
    (Hpq : R2 p q \/ R2 q p)
    (Hpr : R2 p r \/ R2 r p)
    (Hps : R2 p s \/ R2 s p)
    (Hpt : R2 p t \/ R2 t p)
    (Hqr : R2 q r \/ R2 r q)
    (Hqs : R2 q s \/ R2 s q)
    (Hqt : R2 q t \/ R2 t q)
    (Hrs : R2 r s \/ R2 s r)
    (Hrt : R2 r t \/ R2 t r)
    (Hst : R2 s t \/ R2 t s),
  forall (P : Prop), P.
Proof.
  intros B R2 HR2 p q r s t Hcov5 Hinc_ex
    Hpq Hpr Hps Hpt Hqr Hqs Hqt Hrs Hrt Hst P.
  exfalso.
  destruct Hinc_ex as [a [b Hinc]].
  apply Hinc.
  destruct (Hcov5 a) as [Ha | [Ha | [Ha | [Ha | Ha]]]];
  destruct (Hcov5 b) as [Hb | [Hb | [Hb | [Hb | Hb]]]];
    subst a; subst b;
    first
      [ left; apply HR2.(poset_refl)
      | (destruct Hpq as [HRpq | HRqp];
         [left; exact HRpq | right; exact HRqp])
      | (destruct Hpq as [HRpq | HRqp];
         [right; exact HRpq | left; exact HRqp])
      | (destruct Hpr as [HRpr | HRrp];
         [left; exact HRpr | right; exact HRrp])
      | (destruct Hpr as [HRpr | HRrp];
         [right; exact HRpr | left; exact HRrp])
      | (destruct Hps as [HRps | HRsp];
         [left; exact HRps | right; exact HRsp])
      | (destruct Hps as [HRps | HRsp];
         [right; exact HRps | left; exact HRsp])
      | (destruct Hpt as [HRpt | HRtp];
         [left; exact HRpt | right; exact HRtp])
      | (destruct Hpt as [HRpt | HRtp];
         [right; exact HRpt | left; exact HRtp])
      | (destruct Hqr as [HRqr | HRrq];
         [left; exact HRqr | right; exact HRrq])
      | (destruct Hqr as [HRqr | HRrq];
         [right; exact HRqr | left; exact HRrq])
      | (destruct Hqs as [HRqs | HRsq];
         [left; exact HRqs | right; exact HRsq])
      | (destruct Hqs as [HRqs | HRsq];
         [right; exact HRqs | left; exact HRsq])
      | (destruct Hqt as [HRqt | HRtq];
         [left; exact HRqt | right; exact HRtq])
      | (destruct Hqt as [HRqt | HRtq];
         [right; exact HRqt | left; exact HRtq])
      | (destruct Hrs as [HRrs | HRsr];
         [left; exact HRrs | right; exact HRsr])
      | (destruct Hrs as [HRrs | HRsr];
         [right; exact HRrs | left; exact HRsr])
      | (destruct Hrt as [HRrt | HRtr];
         [left; exact HRrt | right; exact HRtr])
      | (destruct Hrt as [HRrt | HRtr];
         [right; exact HRrt | left; exact HRtr])
      | (destruct Hst as [HRst | HRts];
         [left; exact HRst | right; exact HRts])
      | (destruct Hst as [HRst | HRts];
         [right; exact HRst | left; exact HRts]) ].
Qed.

(** Reusable framework: build a 2-element realizer from two rank
    functions on a 5-element carrier.

    The hypotheses bundle the recurring obligations that every n=5
    per-class 2-realizer lemma must discharge:

    - [Hcov]   : every element of [B] is one of [a, b, c, d, e].
    - [Hdist*] : the 10 pairwise distinctness facts for the carrier.
    - [Hrk1_*], [Hrk2_*] : on the 5 carrier elements, the two rank
      functions are pairwise distinct (10 inequalities each).
    - [Hrk1_mono], [Hrk2_mono] : both ranks are monotone on [R2]
      (i.e. [rk1], [rk2] extend [R2] to total orders [L1], [L2]).
    - [Hinter] : the intersection [L1] ∩ [L2] is contained in [R2].
    - [HdistL] : a distinguishing pair witnessing [L1 ≠ L2]
      (some [x, y] with [rk1 x ≤ rk1 y] but [rk2 y < rk2 x]).

    The framework then builds [{L1, L2}] as a 2-element realizer. *)
Lemma n5_two_realizer_framework :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2}
    (a b c d e : B)
    (Hab : a <> b) (Hac : a <> c) (Had : a <> d) (Hae : a <> e)
    (Hbc : b <> c) (Hbd : b <> d) (Hbe : b <> e)
    (Hcd : c <> d) (Hce : c <> e) (Hde : d <> e)
    (Hcov : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e)
    (rk1 rk2 : B -> nat),
  (* rk1 pairwise distinct on the 5 elements *)
  rk1 a <> rk1 b -> rk1 a <> rk1 c -> rk1 a <> rk1 d -> rk1 a <> rk1 e ->
  rk1 b <> rk1 c -> rk1 b <> rk1 d -> rk1 b <> rk1 e ->
  rk1 c <> rk1 d -> rk1 c <> rk1 e ->
  rk1 d <> rk1 e ->
  (* rk2 pairwise distinct on the 5 elements *)
  rk2 a <> rk2 b -> rk2 a <> rk2 c -> rk2 a <> rk2 d -> rk2 a <> rk2 e ->
  rk2 b <> rk2 c -> rk2 b <> rk2 d -> rk2 b <> rk2 e ->
  rk2 c <> rk2 d -> rk2 c <> rk2 e ->
  rk2 d <> rk2 e ->
  (* rk1, rk2 monotone on R2 (extension to L1, L2) *)
  (forall x y : B, R2 x y -> rk1 x <= rk1 y) ->
  (forall x y : B, R2 x y -> rk2 x <= rk2 y) ->
  (* L1 ∩ L2 ⊆ R2 *)
  (forall x y : B, rk1 x <= rk1 y -> rk2 x <= rk2 y -> R2 x y) ->
  (* Distinguishing pair for cardinality 2 *)
  (exists x y : B, rk1 x <= rk1 y /\ rk2 y < rk2 x) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 a b c d e
    Hab Hac Had Hae Hbc Hbd Hbe Hcd Hce Hde Hcov rk1 rk2
    Hrk1_ab Hrk1_ac Hrk1_ad Hrk1_ae Hrk1_bc Hrk1_bd Hrk1_be
    Hrk1_cd Hrk1_ce Hrk1_de
    Hrk2_ab Hrk2_ac Hrk2_ad Hrk2_ae Hrk2_bc Hrk2_bd Hrk2_be
    Hrk2_cd Hrk2_ce Hrk2_de
    Hrk1_mono Hrk2_mono Hinter Hdist.
  (* Injectivity of rk1, rk2 on B (via cover + pairwise distinctness). *)
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcov x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcov y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      try reflexivity;
      exfalso;
      first [ exact (Hrk1_ab Hxy)
            | exact (Hrk1_ab (eq_sym Hxy))
            | exact (Hrk1_ac Hxy)
            | exact (Hrk1_ac (eq_sym Hxy))
            | exact (Hrk1_ad Hxy)
            | exact (Hrk1_ad (eq_sym Hxy))
            | exact (Hrk1_ae Hxy)
            | exact (Hrk1_ae (eq_sym Hxy))
            | exact (Hrk1_bc Hxy)
            | exact (Hrk1_bc (eq_sym Hxy))
            | exact (Hrk1_bd Hxy)
            | exact (Hrk1_bd (eq_sym Hxy))
            | exact (Hrk1_be Hxy)
            | exact (Hrk1_be (eq_sym Hxy))
            | exact (Hrk1_cd Hxy)
            | exact (Hrk1_cd (eq_sym Hxy))
            | exact (Hrk1_ce Hxy)
            | exact (Hrk1_ce (eq_sym Hxy))
            | exact (Hrk1_de Hxy)
            | exact (Hrk1_de (eq_sym Hxy)) ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcov x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcov y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      try reflexivity;
      exfalso;
      first [ exact (Hrk2_ab Hxy)
            | exact (Hrk2_ab (eq_sym Hxy))
            | exact (Hrk2_ac Hxy)
            | exact (Hrk2_ac (eq_sym Hxy))
            | exact (Hrk2_ad Hxy)
            | exact (Hrk2_ad (eq_sym Hxy))
            | exact (Hrk2_ae Hxy)
            | exact (Hrk2_ae (eq_sym Hxy))
            | exact (Hrk2_bc Hxy)
            | exact (Hrk2_bc (eq_sym Hxy))
            | exact (Hrk2_bd Hxy)
            | exact (Hrk2_bd (eq_sym Hxy))
            | exact (Hrk2_be Hxy)
            | exact (Hrk2_be (eq_sym Hxy))
            | exact (Hrk2_cd Hxy)
            | exact (Hrk2_cd (eq_sym Hxy))
            | exact (Hrk2_ce Hxy)
            | exact (Hrk2_ce (eq_sym Hxy))
            | exact (Hrk2_de Hxy)
            | exact (Hrk2_de (eq_sym Hxy)) ]. }
  (* Build L1, L2 as rank-le. *)
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  (* L1 is a total order. *)
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot |].
    intros x y HR. unfold L1. exact (Hrk1_mono x y HR). }
  (* L2 is a total order. *)
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot |].
    intros x y HR. unfold L2. exact (Hrk2_mono x y HR). }
  (* Build realizer set {L1, L2}. *)
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      destruct Hdist as [x [y [Hxy1 Hxy2]]].
      assert (HL1xy : L1 x y) by (unfold L1; exact Hxy1).
      assert (HL2xy : L2 x y) by (rewrite <- Heq; exact HL1xy).
      unfold L2 in HL2xy. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 poset with EXACTLY ONE strict edge.

    The carrier has 5 distinct elements; [R2] is identity plus one
    strict relation [R2 p q] with [p <> q]; no other strict relations.

    Explicit 2-realizer: [L1] orders [p < q < r < s < t] and [L2]
    orders [t < s < r < p < q].  Both extend [R2] (the only required
    pair is [R2 p q], which both [L1] and [L2] satisfy), and their
    intersection on the carrier is exactly [R2] because the only
    off-diagonal pair on which they agree is [(p, q)].  Cardinality
    is 2 because, for instance, [L1 r s] but [~ L2 r s]. *)
Lemma n5_one_edge_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists p q : B,
     p <> q /\ R2 p q /\
     (forall a b : B, R2 a b -> a = b \/ (a = p /\ b = q))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard [p [q [Hpq_neq [HRpq HR_only]]]].
  destruct (@carrier_5_destructure B p q Hcard Hpq_neq)
    as [r [s [t [Hpr [Hps [Hpt [Hqr [Hqs [Hqt [Hrs [Hrt [Hst Hcovers]]]]]]]]]]]].
  (* L1 rank: p=0, q=1, r=2, s=3, t=4.
     L2 rank: t=0, s=1, r=2, p=3, q=4.
     Both ranks extend the only strict edge (p,q) and their
     intersection on the 25 carrier pairs admits only (p,q) and the
     diagonal — both forced into R2 by HR_only / poset_refl. *)
  set (rk1 := fun a : B =>
                if excluded_middle_informative (a = p) then 0%nat
                else if excluded_middle_informative (a = q) then 1%nat
                else if excluded_middle_informative (a = r) then 2%nat
                else if excluded_middle_informative (a = s) then 3%nat
                else 4%nat).
  set (rk2 := fun a : B =>
                if excluded_middle_informative (a = t) then 0%nat
                else if excluded_middle_informative (a = s) then 1%nat
                else if excluded_middle_informative (a = r) then 2%nat
                else if excluded_middle_informative (a = p) then 3%nat
                else 4%nat).
  (* Rank computations on the five elements. *)
  assert (Hrk1_p : rk1 p = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (p = p)); [reflexivity | contradiction]. }
  assert (Hrk1_q : rk1 q = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (q = p)) as [He|_]; [contradiction Hpq_neq; auto |].
    destruct (excluded_middle_informative (q = q)); [reflexivity | contradiction]. }
  assert (Hrk1_r : rk1 r = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (r = p)) as [He|_]; [contradiction Hpr; auto |].
    destruct (excluded_middle_informative (r = q)) as [He|_]; [contradiction Hqr; auto |].
    destruct (excluded_middle_informative (r = r)); [reflexivity | contradiction]. }
  assert (Hrk1_s : rk1 s = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (s = p)) as [He|_]; [contradiction Hps; auto |].
    destruct (excluded_middle_informative (s = q)) as [He|_]; [contradiction Hqs; auto |].
    destruct (excluded_middle_informative (s = r)) as [He|_]; [contradiction Hrs; auto |].
    destruct (excluded_middle_informative (s = s)); [reflexivity | contradiction]. }
  assert (Hrk1_t : rk1 t = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (t = p)) as [He|_]; [contradiction Hpt; auto |].
    destruct (excluded_middle_informative (t = q)) as [He|_]; [contradiction Hqt; auto |].
    destruct (excluded_middle_informative (t = r)) as [He|_]; [contradiction Hrt; auto |].
    destruct (excluded_middle_informative (t = s)) as [He|_]; [contradiction Hst; auto |].
    reflexivity. }
  assert (Hrk2_p : rk2 p = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (p = t)) as [He|_]; [contradiction Hpt; auto |].
    destruct (excluded_middle_informative (p = s)) as [He|_]; [contradiction Hps; auto |].
    destruct (excluded_middle_informative (p = r)) as [He|_]; [contradiction Hpr; auto |].
    destruct (excluded_middle_informative (p = p)); [reflexivity | contradiction]. }
  assert (Hrk2_q : rk2 q = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (q = t)) as [He|_]; [contradiction Hqt; auto |].
    destruct (excluded_middle_informative (q = s)) as [He|_]; [contradiction Hqs; auto |].
    destruct (excluded_middle_informative (q = r)) as [He|_]; [contradiction Hqr; auto |].
    destruct (excluded_middle_informative (q = p)) as [He|_];
      [contradiction Hpq_neq; symmetry; exact He |].
    reflexivity. }
  assert (Hrk2_r : rk2 r = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (r = t)) as [He|_]; [contradiction Hrt; auto |].
    destruct (excluded_middle_informative (r = s)) as [He|_]; [contradiction Hrs; auto |].
    destruct (excluded_middle_informative (r = r)); [reflexivity | contradiction]. }
  assert (Hrk2_s : rk2 s = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (s = t)) as [He|_]; [contradiction Hst; auto |].
    destruct (excluded_middle_informative (s = s)); [reflexivity | contradiction]. }
  assert (Hrk2_t : rk2 t = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (t = t)); [reflexivity | contradiction]. }
  (* Discharge via [n5_two_realizer_framework]. *)
  apply (@n5_two_realizer_framework B R2 HR2 p q r s t
           Hpq_neq Hpr Hps Hpt Hqr Hqs Hqt Hrs Hrt Hst Hcovers rk1 rk2);
    try (rewrite ?Hrk1_p, ?Hrk1_q, ?Hrk1_r, ?Hrk1_s, ?Hrk1_t; lia);
    try (rewrite ?Hrk2_p, ?Hrk2_q, ?Hrk2_r, ?Hrk2_s, ?Hrk2_t; lia).
  - (* rk1 monotone *)
    intros x y HR. destruct (HR_only x y HR) as [Heq | [Hxp Hyq]].
    + subst y. lia.
    + subst x y. rewrite Hrk1_p, Hrk1_q. lia.
  - (* rk2 monotone *)
    intros x y HR. destruct (HR_only x y HR) as [Heq | [Hxp Hyq]].
    + subst y. lia.
    + subst x y. rewrite Hrk2_p, Hrk2_q. lia.
  - (* L1 ∩ L2 ⊆ R2 — 25-case enumeration *)
    intros x y HLa HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRpq
            | exfalso;
              rewrite ?Hrk1_p, ?Hrk1_q, ?Hrk1_r, ?Hrk1_s, ?Hrk1_t in HLa;
              rewrite ?Hrk2_p, ?Hrk2_q, ?Hrk2_r, ?Hrk2_s, ?Hrk2_t in HLb;
              lia ].
  - (* Distinguishing pair: (r, s) since rk1 r = 2 ≤ 3 = rk1 s but rk2 s = 1 < 2 = rk2 r. *)
    exists r, s. rewrite Hrk1_r, Hrk1_s, Hrk2_r, Hrk2_s. lia.
Qed.

(** Sub-case: n=5 poset that is a 3-element chain plus 2 isolated points.

    The carrier has 5 distinct elements [a, b, c, d, e]; [R2] is identity
    plus the chain [a < b < c] and nothing else.  In particular, [d] and
    [e] are incomparable to all of [a, b, c] and to each other.

    Explicit 2-realizer: [L1] orders [a < b < c < d < e]; [L2] orders
    [e < d < a < b < c].  Both extend the chain.  Intersection on the
    carrier agrees only on [(a, b), (a, c), (b, c)] off the diagonal —
    in particular [(d, e)] / [(e, d)] are excluded because [L1] and
    [L2] reverse them.

    Cardinality is 2 because, e.g., [L1 a d] but [~ L2 a d]. *)
Lemma n5_chain3_plus_2isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = b /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac HR_only]]]]]]]]]]]]]]]]]].
  (* Cover {a,b,c,d,e} = B via carrier_5_destructure on (a, b).
     The remaining three elements [r, s, t] are some permutation
     of {c, d, e}. *)
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  (* Every x is one of a, b, c, d, e.  Derive this from Hcov5 by
     showing each of c, d, e is in {r, s, t}. *)
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { (* For any x not in {a, b}, it is in {r, s, t}.  We don't need to
       pin down which, because we will only need [Hcov5 x] to dispatch
       case-splits on rk1/rk2 ranks.  Instead, rephrase: show {c,d,e}
       lies in {r,s,t} and conversely.  Actually easier path: re-derive
       Hcovers via a direct destructure where the named elements are
       (a, b, c) then use carrier_5_destructure differently.

       Use the simpler fact: by Hcov5, every x ∈ {a, b, r, s, t}.
       The five named elements a, b, c, d, e are pairwise distinct,
       so {r, s, t} ⊆ {c, d, e} (each of r, s, t differs from a and b,
       and they are pairwise distinct).  Conversely {c, d, e} ⊆ {r, s, t}
       (each differs from a and b, in a 5-element carrier with 3
       remaining slots).  Then x ∈ {a, b, r, s, t} ⊆ {a, b, c, d, e}. *)
    (* Conclude each of c, d, e ∈ {r, s, t}. *)
    assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    (* And each of r, s, t ∈ {c, d, e}: by pigeonhole on the 3-element
       sets {c, d, e} and {r, s, t} via the injection.  We do this
       concretely by case-splitting. *)
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    (* Now dispatch. *)
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1 rank: a=0, b=1, c=2, d=3, e=4.
     L2 rank: e=0, d=1, a=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [Hxb Hyc]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [Hxb Hyc]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 poset = two disjoint 2-chains plus one isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b] and [c < d];
    no other strict edges (so [e] is isolated and the two chains are
    incomparable).

    2-realizer: L1 = a < b < c < d < e; L2 = e < c < d < a < b.  Both
    extend the two strict edges; the intersection on the carrier
    agrees only on the diagonal plus [(a,b)] and [(c,d)]. *)
Lemma n5_disjoint_chains_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c d /\
     (forall x y : B,
        R2 x y -> x = y \/ (x = a /\ y = b) \/ (x = c /\ y = d))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcd HR_only]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1 rank: a=0, b=1, c=2, d=3, e=4.
     L2 rank: e=0, c=1, d=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [Hxc Hyd]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [Hxc Hyd]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 V-shape plus 2 isolated points.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b] and
    [a < c]; no other strict edges (so [b, c] are incomparable and
    [d, e] are isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < d < a < c < b. *)
Lemma n5_V_plus_2isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\
     (forall x y : B,
        R2 x y -> x = y \/ (x = a /\ y = b) \/ (x = a /\ y = c))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac HR_only]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, d=1, a=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [Hxa Hyc]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [Hxa Hyc]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inverse-V (∧) shape plus 2 isolated points.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < c] and
    [b < c]; no other strict edges (so [a, b] are incomparable and
    [d, e] are isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < d < b < a < c. *)
Lemma n5_inv_V_plus_2isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 b c /\
     (forall x y : B,
        R2 x y -> x = y \/ (x = a /\ y = c) \/ (x = b /\ y = c))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRbc HR_only]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, d=1, b=2, a=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyc] | [Hxb Hyc]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyc] | [Hxb Hyc]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRbc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 N-shape plus isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [c < b],
    [c < d]; no other strict edges (so [e] is isolated and [a,c] are
    incomparable, [a,d] are incomparable, [b,d] are incomparable).

    2-realizer: L1 = a < c < b < d < e; L2 = e < c < d < a < b. *)
Lemma n5_N_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd HR_only]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, b=2, d=3, e=4.
     L2: e=0, c=1, d=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [Hxc Hyd]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [Hxc Hyd]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw upward (a as bottom, three tops b, c, d)
    plus isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [a < c],
    [a < d]; no other strict edges (so [b, c, d] are pairwise
    incomparable and [e] is isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < a < d < c < b. *)
Lemma n5_3claw_up_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad HR_only]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, a=1, d=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [Hxa Hyd]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [Hxa Hyd]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw downward (three bottoms a, b, c, one top d)
    plus isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < d], [b < d],
    [c < d]; no other strict edges (so [a, b, c] are pairwise
    incomparable and [e] is isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < c < b < a < d. *)
Lemma n5_3claw_down_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a d /\ R2 b d /\ R2 c d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = d) \/ (x = b /\ y = d) \/ (x = c /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRad [HRbd [HRcd HR_only]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, c=1, b=2, a=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyd] | [[Hxb Hyd] | [Hxc Hyd]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyd] | [[Hxb Hyd] | [Hxc Hyd]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRad
            | exact HRbd
            | exact HRcd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 poset = 3-element chain plus a separate 2-element
    chain.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [b < c],
    [a < c] (chain), and [d < e] (separate chain).  No other strict
    edges, so [{a,b,c}] and [{d,e}] are incomparable across chains.

    2-realizer: L1 = a < b < c < d < e; L2 = d < e < a < b < c. *)
Lemma n5_disjoint_chain3_chain2_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/
         (x = a /\ y = c) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRde HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: d=0, e=1, a=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR.
    destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [Hxd Hye]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR.
    destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [Hxd Hye]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 V-shape plus a disjoint 2-chain.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [a < c],
    [d < e]; no other strict edges (so [b, c] are incomparable and
    [d, e] form a separate 2-chain disjoint from [{a, b, c}]).

    2-realizer: L1 = a < b < c < d < e; L2 = d < e < a < c < b. *)
Lemma n5_V_plus_chain_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRde HR_only]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: d=0, e=1, a=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [Hxd Hye]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [Hxd Hye]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inverse-V (∧) shape plus a disjoint 2-chain.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < c], [b < c],
    [d < e]; no other strict edges (so [a, b] are incomparable and
    [d, e] form a separate 2-chain disjoint from [{a, b, c}]).

    2-realizer: L1 = a < b < c < d < e; L2 = d < e < b < a < c. *)
Lemma n5_inv_V_plus_chain_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 b c /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = b /\ y = c) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRbc [HRde HR_only]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: d=0, e=1, b=2, a=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [Hxd Hye]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [Hxd Hye]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRbc
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-chain plus one isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; [a < b < c < d] forms a
    chain (with all six transitive strict edges) and [e] is isolated.

    2-realizer: L1 = a < b < c < d < e; L2 = e < a < b < c < d. *)
Lemma n5_chain4_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 c d /\ R2 a c /\ R2 a d /\ R2 b d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = b /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRcd [HRac [HRad [HRbd HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, a=1, b=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] | [[Hxa Hyd] | [Hxb Hyd]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] | [[Hxa Hyd] | [Hxb Hyd]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRcd
            | exact HRac
            | exact HRad
            | exact HRbd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1de : L1 d e) by (unfold L1; rewrite Hrk1_d, Hrk1_e; lia).
      assert (HL2de : L2 d e) by (rewrite <- Heq; exact HL1de).
      unfold L2 in HL2de. rewrite Hrk2_d, Hrk2_e in HL2de. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 bowtie (K_{2,2}) plus isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < c], [a < d],
    [b < c], [b < d]; no other strict edges (so [a, b] incomparable,
    [c, d] incomparable, [e] isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < b < a < d < c. *)
Lemma n5_bowtie_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 a d /\ R2 b c /\ R2 b d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = c) \/ (x = b /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRad [HRbc [HRbd HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, b=1, a=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [Hxb Hyd]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [Hxb Hyd]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRad
            | exact HRbc
            | exact HRbd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 diamond plus isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [a < c],
    [b < d], [c < d] together with the transitive edge [a < d]; no
    other strict edges (so [b, c] are incomparable and [e] is isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < a < c < b < d. *)
Lemma n5_diamond_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 a d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/ (x = a /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRad HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, a=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [Hxa Hyd]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [Hxa Hyd]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRad
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 P-shape (3-chain with one pendant) plus isolated.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [b < c],
    [a < d], together with the transitive edge [a < c]; no other strict
    edges (so [b, d] and [c, d] are incomparable, and [e] is isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < a < d < b < c. *)
Lemma n5_pendant_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a d /\ R2 a c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/
         (x = a /\ y = d) \/ (x = a /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRad [HRac HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, a=1, d=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyd] | [Hxa Hyc]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyd] | [Hxa Hyc]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRad
            | exact HRac
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bd : L1 b d) by (unfold L1; rewrite Hrk1_b, Hrk1_d; lia).
      assert (HL2bd : L2 b d) by (rewrite <- Heq; exact HL1bd).
      unfold L2 in HL2bd. rewrite Hrk2_b, Hrk2_d in HL2bd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 N-shape extended by a pendant edge.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [c < b],
    [c < d], [d < e], together with the transitive edge [c < e]; no
    other strict edges (so [a, c] incomparable, [a, d] incomparable,
    [a, e] incomparable, [b, d] incomparable, [b, e] incomparable).

    2-realizer: L1 = a < c < b < d < e; L2 = c < d < e < a < b. *)
Lemma n5_N_plus_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 d e /\ R2 c e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/
         (x = c /\ y = d) \/ (x = d /\ y = e) \/ (x = c /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd [HRde [HRce HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, b=2, d=3, e=4.
     L2: c=0, d=1, e=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He|_]; [contradiction Hbc_neq; auto; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxd Hye] | [Hxc Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxd Hye] | [Hxc Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRde
            | exact HRce
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-up extended by a pendant edge from one leaf.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [a < c],
    [a < d], [d < e], together with the transitive edge [a < e]; no
    other strict edges (so [b, c], [b, d], [c, d], [b, e], [c, e] are
    incomparable).

    2-realizer: L1 = a < b < c < d < e; L2 = a < d < e < c < b. *)
Lemma n5_3claw_up_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 d e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = a /\ y = d) \/ (x = d /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRde [HRae HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, d=1, e=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxd Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxd Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRde
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-down extended by a pendant edge into one leaf.

    Carrier [a, b, c, d, e] pairwise distinct; edges [b < a], [c < a],
    [d < a], [e < d], together with the transitive edge [e < a]; no
    other strict edges (so [b, c], [b, d], [c, d], [b, e], [c, e] are
    incomparable).

    2-realizer: L1 = b < c < e < d < a; L2 = e < d < c < b < a. *)
Lemma n5_3claw_down_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 c a /\ R2 d a /\ R2 e d /\ R2 e a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = c /\ y = a) \/
         (x = d /\ y = a) \/ (x = e /\ y = d) \/ (x = e /\ y = a)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRca [HRda [HRed [HRea HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, c=1, e=2, d=3, a=4.
     L2: e=0, d=1, c=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He|_]; [contradiction Had_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [[Hxe Hyd] | [Hxe Hya]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [[Hxe Hyd] | [Hxe Hya]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRca
            | exact HRda
            | exact HRed
            | exact HRea
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 Y-up shape plus isolated point.

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [b < c],
    [b < d], with transitive edges [a < c], [a < d]; no other strict
    edges (so [c, d] are incomparable, and [e] is isolated).

    2-realizer: L1 = a < b < c < d < e; L2 = e < a < b < d < c. *)
Lemma n5_Y_up_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 b d /\ R2 a c /\ R2 a d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/
         (x = b /\ y = d) \/ (x = a /\ y = c) \/ (x = a /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRbd [HRac HRad_HRonly]]]]]]]]]]]]]]]]]]].
  destruct HRad_HRonly as [HRad HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, a=1, b=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] | [[Hxa Hyc] | [Hxa Hyd]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] | [[Hxa Hyc] | [Hxa Hyd]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRbd
            | exact HRac
            | exact HRad
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 W-shape (5-fence / zigzag).

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [c < b],
    [c < d], [e < d]; no other strict edges (so [a, c], [a, d], [a, e],
    [b, d], [b, e], [c, e], [b, c] (in incomp direction) all incomparable
    except for the four R-edges).  No transitive edges arise because
    the only chains have length 2.

    2-realizer: L1 = a < c < b < e < d; L2 = e < c < d < a < b. *)
Lemma n5_fence_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/
         (x = c /\ y = d) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd [HRed HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, b=2, e=3, d=4.
     L2: e=0, c=1, d=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [Hxe Hyd]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [Hxe Hyd]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 Y-down shape plus isolated point.

    Dual of [n5_Y_up_plus_isolated_two_realizer].  Carrier
    [a, b, c, d, e] pairwise distinct; edges [c < b], [d < b], [b < a],
    with transitive edges [c < a], [d < a]; no other strict edges
    (so [c, d] are incomparable, and [e] is isolated).

    2-realizer: L1 = c < d < b < a < e; L2 = e < d < c < b < a. *)
Lemma n5_Y_down_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c b /\ R2 d b /\ R2 b a /\ R2 c a /\
     (R2 d a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = b) \/ (x = d /\ y = b) \/
         (x = b /\ y = a) \/ (x = c /\ y = a) \/ (x = d /\ y = a))))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRcb [HRdb [HRba [HRca [HRda HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: c=0, d=1, b=2, a=3, e=4.
     L2: e=0, d=1, c=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_c : rk1 c = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = c)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = c)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxd Hyb] | [[Hxb Hya] | [[Hxc Hya] | [Hxd Hya]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxd Hyb] | [[Hxb Hya] | [[Hxc Hya] | [Hxd Hya]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRcb
            | exact HRdb
            | exact HRba
            | exact HRca
            | exact HRda
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 M-shape (dual of fence/W).

    Dual of [n5_fence_two_realizer].  Carrier [a, b, c, d, e] pairwise
    distinct; edges [b < a], [b < c], [d < c], [d < e]; no other strict
    edges.  In this orientation, [b, d] sit at the bottom; [a, c, e]
    sit above, with [b] meeting [a] and [c], and [d] meeting [c] and
    [e].  All chains have length 2, so no transitive edges arise.

    2-realizer: L1 = d < e < b < c < a; L2 = b < a < d < c < e. *)
Lemma n5_M_shape_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/
         (x = d /\ y = c) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc [HRde HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, e=1, b=2, c=3, a=4.
     L2: b=0, a=1, d=2, c=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxd Hye]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxd Hye]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1eb : L1 e b) by (unfold L1; rewrite Hrk1_e, Hrk1_b; lia).
      assert (HL2eb : L2 e b) by (rewrite <- Heq; exact HL1eb).
      unfold L2 in HL2eb. rewrite Hrk2_e, Hrk2_b in HL2eb. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-claw-up (one bottom dominates four tops).

    Carrier [a, b, c, d, e] pairwise distinct; edges [a < b], [a < c],
    [a < d], [a < e]; no other strict edges (so [b, c, d, e] are
    pairwise incomparable).  This is the "star" shape K_{1, 4} oriented
    upward.

    2-realizer: L1 = a < b < c < d < e; L2 = a < e < d < c < b. *)
Lemma n5_4claw_up_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = a /\ y = d) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRae HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, e=1, d=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [Hxa Hye]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [Hxa Hye]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-claw-down (one top dominates four bottoms).

    Dual of [n5_4claw_up_two_realizer].  Carrier [a, b, c, d, e]
    pairwise distinct; edges [b < a], [c < a], [d < a], [e < a]; no
    other strict edges (so [b, c, d, e] are pairwise incomparable).
    This is the "star" shape K_{1, 4} oriented downward.

    2-realizer: L1 = b < c < d < e < a; L2 = e < d < c < b < a. *)
Lemma n5_4claw_down_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 c a /\ R2 d a /\ R2 e a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = c /\ y = a) \/
         (x = d /\ y = a) \/ (x = e /\ y = a)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRca [HRda [HRea HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, c=1, d=2, e=3, a=4.
     L2: e=0, d=1, c=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [Hxe Hya]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [Hxe Hya]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRca
            | exact HRda
            | exact HRea
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inverted-N plus isolated point.

    Dual of [n5_N_plus_isolated_two_realizer].  Carrier [a, b, c, d, e]
    pairwise distinct; edges [b < a], [b < c], [d < c]; no other strict
    edges (so [b, d] are incomparable, [a, c], [a, d] are incomparable,
    and [e] is isolated).  The shape is the dual N (or "Z"): two
    bottoms [b, d] each pointing up, with [b] shared between the two
    tops [a, c] and [d] joining only [c].

    2-realizer: L1 = e < d < b < c < a; L2 = b < a < d < c < e. *)
Lemma n5_inv_N_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc HR_only]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, b=2, c=3, a=4.
     L2: b=0, a=1, d=2, c=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [Hxd Hyc]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [Hxd Hyc]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ed : L1 e d) by (unfold L1; rewrite Hrk1_e, Hrk1_d; lia).
      assert (HL2ed : L2 e d) by (rewrite <- Heq; exact HL1ed).
      unfold L2 in HL2ed. rewrite Hrk2_e, Hrk2_d in HL2ed. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 chain-3 plus V at top (chain3 + 2 pendants at top).

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges: chain
    [a < b], [b < c] with transitive [a < c], plus V at top
    [c < d], [c < e] with transitive [a < d], [a < e], [b < d], [b < e].
    No edge between [d, e] (they are incomparable siblings).  Nine
    strict edges in total.

    2-realizer: L1 = a < b < c < d < e; L2 = a < b < c < e < d. *)
Lemma n5_chain3_plus_V_top_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 c d /\ R2 c e /\
     (R2 a d /\ R2 a e /\ R2 b d /\ R2 b e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = c /\ y = d) \/ (x = c /\ y = e) \/
         (x = a /\ y = d) \/ (x = a /\ y = e) \/
         (x = b /\ y = d) \/ (x = b /\ y = e))))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRcd [HRce
       [HRad [HRae [HRbd [HRbe HR_only]]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, b=1, c=2, e=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxc Hyd] | [[Hxc Hye] |
              [[Hxa Hyd] | [[Hxa Hye] |
              [[Hxb Hyd] | [Hxb Hye]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxc Hyd] | [[Hxc Hye] |
              [[Hxa Hyd] | [[Hxa Hye] |
              [[Hxb Hyd] | [Hxb Hye]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRcd
            | exact HRce
            | exact HRad
            | exact HRae
            | exact HRbd
            | exact HRbe
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1de : L1 d e) by (unfold L1; rewrite Hrk1_d, Hrk1_e; lia).
      assert (HL2de : L2 d e) by (rewrite <- Heq; exact HL1de).
      unfold L2 in HL2de. rewrite Hrk2_d, Hrk2_e in HL2de. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 chain-3 plus inv-V at bottom (2 pendants at bottom + chain3).

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges: chain
    [a < b], [b < c] with transitive [a < c], plus inv-V at bottom
    [d < a], [e < a] with transitive [d < b], [d < c], [e < b], [e < c].
    No edge between [d, e] (they are incomparable siblings).  Nine
    strict edges in total.  This is the dual of [n5_chain3_plus_V_top].

    2-realizer: L1 = d < e < a < b < c; L2 = e < d < a < b < c. *)
Lemma n5_chain3_plus_inv_V_bottom_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 d a /\ R2 e a /\
     (R2 d b /\ R2 d c /\ R2 e b /\ R2 e c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = d /\ y = a) \/ (x = e /\ y = a) \/
         (x = d /\ y = b) \/ (x = d /\ y = c) \/
         (x = e /\ y = b) \/ (x = e /\ y = c))))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRda [HRea
       [HRdb [HRdc [HReb [HRec HR_only]]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, e=1, a=2, b=3, c=4.
     L2: e=0, d=1, a=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxd Hya] | [[Hxe Hya] |
              [[Hxd Hyb] | [[Hxd Hyc] |
              [[Hxe Hyb] | [Hxe Hyc]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxd Hya] | [[Hxe Hya] |
              [[Hxd Hyb] | [[Hxd Hyc] |
              [[Hxe Hyb] | [Hxe Hyc]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRda
            | exact HRea
            | exact HRdb
            | exact HRdc
            | exact HReb
            | exact HRec
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1de : L1 d e) by (unfold L1; rewrite Hrk1_d, Hrk1_e; lia).
      assert (HL2de : L2 d e) by (rewrite <- Heq; exact HL1de).
      unfold L2 in HL2de. rewrite Hrk2_d, Hrk2_e in HL2de. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 diamond with pendant above top.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form a
    diamond on [a, b, c, d] (i.e. [a < b], [a < c], [b < d], [c < d],
    transitive [a < d]) together with [d < e] above the diamond's top,
    yielding transitive edges [a < e], [b < e], [c < e].  No edge
    between [b, c] (they are incomparable siblings in the diamond).
    Nine strict edges in total.

    2-realizer: L1 = a < b < c < d < e; L2 = a < c < b < d < e. *)
Lemma n5_diamond_pendant_above_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 a d /\ R2 d e /\
     (R2 a e /\ R2 b e /\ R2 c e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/ (x = a /\ y = d) \/
         (x = d /\ y = e) \/
         (x = a /\ y = e) \/ (x = b /\ y = e) \/ (x = c /\ y = e))))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRad [HRde
       [HRae [HRbe [HRce HR_only]]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, c=1, b=2, d=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] |
              [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] |
              [[Hxd Hye] |
              [[Hxa Hye] | [[Hxb Hye] | [Hxc Hye]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] |
              [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] |
              [[Hxd Hye] |
              [[Hxa Hye] | [[Hxb Hye] | [Hxc Hye]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRad
            | exact HRde
            | exact HRae
            | exact HRbe
            | exact HRce
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 diamond with pendant below bottom.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form a
    diamond on [a, b, c, d] (i.e. [a < b], [a < c], [b < d], [c < d],
    transitive [a < d]) together with [e < a] below the diamond's bottom,
    yielding transitive edges [e < b], [e < c], [e < d].  No edge
    between [b, c] (they are incomparable siblings in the diamond).
    Nine strict edges in total.

    2-realizer: L1 = e < a < b < c < d; L2 = e < a < c < b < d. *)
Lemma n5_diamond_pendant_below_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 a d /\ R2 e a /\
     (R2 e b /\ R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/ (x = a /\ y = d) \/
         (x = e /\ y = a) \/
         (x = e /\ y = b) \/ (x = e /\ y = c) \/ (x = e /\ y = d))))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRad [HRea
       [HReb [HRec [HRed HR_only]]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, a=1, b=2, c=3, d=4.
     L2: e=0, a=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] |
              [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] |
              [[Hxe Hya] |
              [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] |
              [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] |
              [[Hxe Hya] |
              [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRad
            | exact HRea
            | exact HReb
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 bowtie with pendant above one top.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form a
    bowtie K_{2,2} on [a, b, c, d] (i.e. [a < c], [a < d], [b < c],
    [b < d], with [a, b] incomparable and [c, d] incomparable),
    together with [c < e] (pendant above [c]); transitive edges
    [a < e], [b < e].  No edge between [d, e] (since [d] is not below
    [c]).  Seven strict edges in total.

    2-realizer: L1 = a < b < d < c < e; L2 = b < a < c < e < d. *)
Lemma n5_bowtie_pendant_up_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 a d /\ R2 b c /\ R2 b d /\ R2 c e /\
     (R2 a e /\ R2 b e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = c) \/ (x = b /\ y = d) \/
         (x = c /\ y = e) \/
         (x = a /\ y = e) \/ (x = b /\ y = e))))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRad [HRbc [HRbd [HRce
       [HRae [HRbe HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, d=2, c=3, e=4.
     L2: b=0, a=1, c=2, e=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxc Hye] |
              [[Hxa Hye] | [Hxb Hye]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxc Hye] |
              [[Hxa Hye] | [Hxb Hye]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRad
            | exact HRbc
            | exact HRbd
            | exact HRce
            | exact HRae
            | exact HRbe
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 bowtie with pendant below one bottom.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form a
    bowtie K_{2,2} on [a, b, c, d] (i.e. [a < c], [a < d], [b < c],
    [b < d], with [a, b] incomparable and [c, d] incomparable),
    together with [e < a] (pendant below [a]); transitive edges
    [e < c], [e < d].  No edge between [b, e] (since [b] is not above
    [a]).  Seven strict edges in total.

    2-realizer: L1 = e < a < b < c < d; L2 = b < e < a < d < c. *)
Lemma n5_bowtie_pendant_down_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 a d /\ R2 b c /\ R2 b d /\ R2 e a /\
     (R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = c) \/ (x = b /\ y = d) \/
         (x = e /\ y = a) \/
         (x = e /\ y = c) \/ (x = e /\ y = d))))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRad [HRbc [HRbd [HRea
       [HRec [HRed HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, a=1, b=2, c=3, d=4.
     L2: b=0, e=1, a=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxe Hya] |
              [[Hxe Hyc] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxe Hya] |
              [[Hxe Hyc] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRad
            | exact HRbc
            | exact HRbd
            | exact HRea
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 P-shape (3-chain with one top pendant) plus isolated.

    Dual of [n5_pendant_plus_isolated_two_realizer].  Carrier
    [a, b, c, d, e] pairwise distinct; edges [a < b], [b < c], [d < c],
    with transitive edge [a < c]; no other strict edges (so [a, d] and
    [b, d] are incomparable, and [e] is isolated).  The vertex [c] has
    two parents [b] and [d], with one parent on a longer chain [a < b].

    2-realizer: L1 = a < b < d < c < e; L2 = e < d < a < b < c. *)
Lemma n5_chain3_top_pendant_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 d c /\ R2 a c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/
         (x = d /\ y = c) \/ (x = a /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRdc [HRac HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, d=2, c=3, e=4.
     L2: e=0, d=1, a=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxa Hyc]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxa Hyc]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRdc
            | exact HRac
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inverted-V with pendant above the apex.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form an
    inverted-V [a < c], [b < c] together with [c < d] (a pendant above
    the apex [c]); transitives [a < d] and [b < d] complete the order.
    Vertex [e] is isolated.  Five direct + two transitive = five
    distinct strict pairs: [a < c], [b < c], [c < d], [a < d], [b < d].

    2-realizer: L1 = a < b < c < d < e; L2 = e < b < a < c < d. *)
Lemma n5_inv_V_pendant_top_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 b c /\ R2 c d /\ R2 a d /\ R2 b d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = d) \/ (x = b /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRbc [HRcd [HRad [HRbd HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, b=1, a=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyd] | [Hxb Hyd]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyd] | [Hxb Hyd]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRbc
            | exact HRcd
            | exact HRad
            | exact HRbd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 V-shape with pendant below the common bottom.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form a
    V-shape [a < b], [a < c] together with [d < a] (a pendant below
    [a]); transitives [d < b] and [d < c] complete the order.  Vertex
    [e] is isolated.  Five strict pairs: [a < b], [a < c], [d < a],
    [d < b], [d < c].

    2-realizer: L1 = d < a < b < c < e; L2 = e < d < a < c < b. *)
Lemma n5_V_pendant_bot_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 d a /\ R2 d b /\ R2 d c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = d /\ y = a) \/
         (x = d /\ y = b) \/ (x = d /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRda [HRdb [HRdc HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, a=1, b=2, c=3, e=4.
     L2: e=0, d=1, a=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxd Hya] | [[Hxd Hyb] | [Hxd Hyc]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxd Hya] | [[Hxd Hyb] | [Hxd Hyc]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRda
            | exact HRdb
            | exact HRdc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-chain extended with a pendant below the top.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form a
    4-chain [a < b < c < d] (with all three transitives [a<c], [a<d],
    [b<d]) plus an extra pendant [e < d] below the top.  Vertices [a],
    [b], [c] are pairwise incomparable with [e].  Seven strict pairs.

    2-realizer: L1 = a < b < c < e < d; L2 = e < a < b < c < d. *)
Lemma n5_chain4_top_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 c d /\ R2 a c /\ R2 a d /\ R2 b d /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRcd [HRac [HRad [HRbd [HRed HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, e=3, d=4.
     L2: e=0, a=1, b=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyd] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyd] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRcd
            | exact HRac
            | exact HRad
            | exact HRbd
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ae : L1 a e) by (unfold L1; rewrite Hrk1_a, Hrk1_e; lia).
      assert (HL2ae : L2 a e) by (rewrite <- Heq; exact HL1ae).
      unfold L2 in HL2ae. rewrite Hrk2_a, Hrk2_e in HL2ae. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-chain extended with a pendant above the bottom.

    Dual of [n5_chain4_top_pendant_two_realizer].  Carrier
    [a, b, c, d, e] pairwise distinct.  Strict edges form a 4-chain
    [a < b < c < d] (with all three transitives [a<c], [a<d], [b<d])
    plus an extra pendant [a < e] above the bottom.  Vertex [e] is
    incomparable to [b], [c], [d].  Seven strict pairs.

    2-realizer: L1 = a < e < b < c < d; L2 = a < b < c < d < e. *)
Lemma n5_chain4_bot_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 c d /\ R2 a c /\ R2 a d /\ R2 b d /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRcd [HRac [HRad [HRbd [HRae HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, e=1, b=2, c=3, d=4.
     L2: a=0, b=1, c=2, d=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyd] | [Hxa Hye]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyd] | [Hxa Hye]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRcd
            | exact HRac
            | exact HRad
            | exact HRbd
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1eb : L1 e b) by (unfold L1; rewrite Hrk1_e, Hrk1_b; lia).
      assert (HL2eb : L2 e b) by (rewrite <- Heq; exact HL1eb).
      unfold L2 in HL2eb. rewrite Hrk2_e, Hrk2_b in HL2eb. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 Y-down with a pendant below one branch.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form a
    Y-down structure on [a, b, c, d] (so [c<b], [d<b], [b<a], with
    transitives [c<a], [d<a]) together with [e<c] below one of the
    Y-arms; further transitives [e<b], [e<a] arise.  No edge between
    [c,d] (they are incomparable Y-branches) and no edge between [d,e].
    Eight strict pairs.

    2-realizer: L1 = e < c < d < b < a; L2 = d < e < c < b < a. *)
Lemma n5_Y_down_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c b /\ R2 d b /\ R2 b a /\ R2 c a /\ R2 d a /\
     R2 e c /\ R2 e b /\ R2 e a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = b) \/ (x = d /\ y = b) \/ (x = b /\ y = a) \/
         (x = c /\ y = a) \/ (x = d /\ y = a) \/
         (x = e /\ y = c) \/ (x = e /\ y = b) \/ (x = e /\ y = a)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRcb [HRdb [HRba [HRca [HRda
       [HRec [HReb [HRea HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, c=1, d=2, b=3, a=4.
     L2: d=0, e=1, c=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxd Hyb] | [[Hxb Hya] |
              [[Hxc Hya] | [[Hxd Hya] |
              [[Hxe Hyc] | [[Hxe Hyb] | [Hxe Hya]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxd Hyb] | [[Hxb Hya] |
              [[Hxc Hya] | [[Hxd Hya] |
              [[Hxe Hyc] | [[Hxe Hyb] | [Hxe Hya]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRcb
            | exact HRdb
            | exact HRba
            | exact HRca
            | exact HRda
            | exact HRec
            | exact HReb
            | exact HRea
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 Y-up shape with a pendant below the base.

    Carrier [a, b, c, d, e] pairwise distinct.  Y-up shape: [a < b],
    [b < c], [b < d], plus transitives [a < c], [a < d].  Pendant below
    [a]: [e < a], with transitives [e < b], [e < c], [e < d].  Total 9
    R-edges.  Only incomparable pair: [{c, d}].

    2-realizer: [L1] orders [e < a < b < c < d];
    [L2] orders [e < a < b < d < c]. *)
Lemma n5_Y_up_pendant_below_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 b d /\ R2 a c /\ R2 a d /\
     R2 e a /\ R2 e b /\ R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = b /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = e /\ y = a) \/ (x = e /\ y = b) \/ (x = e /\ y = c) \/
         (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRbd [HRac [HRad
       [HRea [HReb [HRec [HRed HR_only]]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, a=1, b=2, c=3, d=4.
     L2: e=0, a=1, b=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxe Hya] | [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxe Hya] | [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRbd
            | exact HRac
            | exact HRad
            | exact HRea
            | exact HReb
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 Y-up shape with a pendant above one branch (top).

    Carrier [a, b, c, d, e] pairwise distinct.  Y-up shape: [a < b],
    [b < c], [b < d], plus transitives [a < c], [a < d].  Pendant above
    branch [c]: [c < e], with transitives [b < e], [a < e].  Total 8
    R-edges.  Incomparable pairs: [{c, d}], [{d, e}].

    2-realizer: [L1] orders [a < b < c < e < d];
    [L2] orders [a < b < d < c < e]. *)
Lemma n5_Y_up_pendant_above_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 b d /\ R2 a c /\ R2 a d /\
     R2 c e /\ R2 b e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = b /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = c /\ y = e) \/ (x = b /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRbd [HRac [HRad
       [HRce [HRbe [HRae HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, e=3, d=4.
     L2: a=0, b=1, d=2, c=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxc Hye] | [[Hxb Hye] | [Hxa Hye]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] |
              [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxc Hye] | [[Hxb Hye] | [Hxa Hye]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRbd
            | exact HRac
            | exact HRad
            | exact HRce
            | exact HRbe
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 T-shape extended with a pendant below the top branch.

    Carrier [a, b, c, d, e] pairwise distinct.  T-shape: 3-chain
    [a < b < c] with a branch [b < d] (so [a < c], [a < d]).  Pendant
    [e < d] below the branch tip [d].  Total 6 R-edges:
    [a < b], [b < c], [a < c], [b < d], [a < d], [e < d].  Incomparable
    pairs: [{c, d}], [{e, a}], [{e, b}], [{e, c}].

    2-realizer: [L1] orders [e < a < b < d < c];
    [L2] orders [a < b < c < e < d]. *)
Lemma n5_T_shape_extended_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 b d /\ R2 a d /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = a /\ y = d) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRbd [HRad [HRed HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, a=1, b=2, d=3, c=4.
     L2: a=0, b=1, c=2, e=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxb Hyd] | [[Hxa Hyd] | [Hxe Hyd]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxb Hyd] | [[Hxa Hyd] | [Hxe Hyd]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRbd
            | exact HRad
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 d c) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 d c) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-up with a chain growing from one leaf.

    Carrier [a, b, c, d, e] pairwise distinct.  3-claw-up apex [a] at
    bottom, three leaves [b, c, d]: [a < b], [a < c], [a < d].  Chain
    growing from leaf [c]: [c < e], with transitive [a < e].  Total 5
    R-edges.  Incomparable pairs: [{b, c}], [{b, d}], [{c, d}],
    [{b, e}], [{d, e}].

    2-realizer: [L1] orders [a < c < e < d < b];
    [L2] orders [a < b < d < c < e]. *)
Lemma n5_3claw_up_chain_in_leaf_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 c e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = c /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRce [HRae HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, e=2, d=3, b=4.
     L2: a=0, b=1, d=2, c=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxc Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxc Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRce
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-down with a chain growing from one leaf.

    Carrier [a, b, c, d, e] pairwise distinct.  3-claw-down apex [a] at
    top, three leaves [b, c, d]: [b < a], [c < a], [d < a].  Chain
    growing below leaf [c]: [e < c], with transitive [e < a].  Total 5
    R-edges.  Incomparable pairs: [{b, c}], [{b, d}], [{c, d}],
    [{b, e}], [{d, e}].

    2-realizer: [L1] orders [b < d < e < c < a];
    [L2] orders [e < c < d < b < a]. *)
Lemma n5_3claw_down_chain_in_leaf_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 c a /\ R2 d a /\ R2 e c /\ R2 e a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = c /\ y = a) \/ (x = d /\ y = a) \/
         (x = e /\ y = c) \/ (x = e /\ y = a)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRca [HRda [HRec [HRea HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, d=1, e=2, c=3, a=4.
     L2: e=0, c=1, d=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] |
              [[Hxe Hyc] | [Hxe Hya]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] |
              [[Hxe Hyc] | [Hxe Hya]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRca
            | exact HRda
            | exact HRec
            | exact HRea
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 d c) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 d c) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 X-shape (hourglass).

    Carrier [a, b, c, d, e] pairwise distinct.  Two minima [a], [b]
    both below [c]; two maxima [d], [e] both above [c]: [a < c],
    [b < c], [c < d], [c < e].  Transitive closure adds [a < d],
    [a < e], [b < d], [b < e].  Total 8 R-edges.  Incomparable pairs:
    [{a, b}], [{d, e}].

    2-realizer: [L1] orders [a < b < c < d < e];
    [L2] orders [b < a < c < e < d]. *)
Lemma n5_X_shape_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 b c /\ R2 c d /\ R2 c e /\
     R2 a d /\ R2 a e /\ R2 b d /\ R2 b e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = b /\ y = c) \/
         (x = c /\ y = d) \/ (x = c /\ y = e) \/
         (x = a /\ y = d) \/ (x = a /\ y = e) \/
         (x = b /\ y = d) \/ (x = b /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRbc [HRcd [HRce [HRad [HRae [HRbd [HRbe HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: b=0, a=1, c=2, e=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxc Hye] |
              [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyd] | [Hxb Hye]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxc Hye] |
              [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyd] | [Hxb Hye]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRbc
            | exact HRcd
            | exact HRce
            | exact HRad
            | exact HRae
            | exact HRbd
            | exact HRbe
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 bowtie with top chain edge + isolated.

    Carrier [a, b, c, d, e] pairwise distinct.  Bowtie [a < c], [a < d],
    [b < c], [b < d] with extra chain edge [c < d] turning the top into
    a chain.  Element [e] is isolated.  Total 5 R-edges (no extra
    transitive edges because [c < d] is the only new relation, and
    [a < c < d] already gives [a < d] which we have, similarly for [b]).
    Incomparable pairs: [{a, b}], [{a, e}], [{b, e}], [{c, e}], [{d, e}].

    2-realizer: [L1] orders [a < b < c < d < e];
    [L2] orders [e < b < a < c < d]. *)
Lemma n5_bowtie_top_chain_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 a d /\ R2 b c /\ R2 b d /\ R2 c d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = c) \/ (x = b /\ y = d) \/
         (x = c /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRad [HRbc [HRbd [HRcd HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, b=1, a=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [[Hxb Hyd] | [Hxc Hyd]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [[Hxb Hyd] | [Hxc Hyd]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRad
            | exact HRbc
            | exact HRbd
            | exact HRcd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 bowtie with bottom chain edge + isolated.

    Carrier [a, b, c, d, e] pairwise distinct.  Bottom chain edge
    [a < b] together with [a < c], [a < d], [b < c], [b < d].  Element
    [e] isolated.  Total 5 R-edges (with [c, d] incomparable at top).
    Incomparable pairs: [{c, d}], [{a, e}], [{b, e}], [{c, e}],
    [{d, e}].

    2-realizer: [L1] orders [a < b < c < d < e];
    [L2] orders [e < a < b < d < c]. *)
Lemma n5_bowtie_bot_chain_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 b c /\ R2 b d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = c) \/ (x = b /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRbc [HRbd HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: e=0, a=1, b=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [Hxb Hyd]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [Hxb Hyd]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRbc
            | exact HRbd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-chain with pendant below the third element.

    Carrier [a, b, c, d, e] pairwise distinct.  Chain [a < b < c < d]
    (4-chain) with extra pendant [e < c] (so by transitivity [e < d]).
    Element [e] is incomparable to [a] and [b].  Total 8 R-edges (the
    six chain edges plus [e < c] and [e < d]).  Incomparable pairs:
    [{e, a}], [{e, b}].

    2-realizer: [L1] orders [a < b < e < c < d];
    [L2] orders [e < a < b < c < d]. *)
Lemma n5_chain4_pendant_below_third_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 c d /\ R2 a c /\ R2 a d /\ R2 b d /\
     R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = e /\ y = c) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRcd [HRac [HRad [HRbd [HRec HRed_HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct HRed_HR_only as [HRed HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, e=2, c=3, d=4.
     L2: e=0, a=1, b=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRcd
            | exact HRac
            | exact HRad
            | exact HRbd
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ae : L1 a e) by (unfold L1; rewrite Hrk1_a, Hrk1_e; lia).
      assert (HL2ae : L2 a e) by (rewrite <- Heq; exact HL1ae).
      unfold L2 in HL2ae. rewrite Hrk2_a, Hrk2_e in HL2ae. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-chain with pendant above the second element.

    Carrier [a, b, c, d, e] pairwise distinct.  Chain [a < b < c < d]
    (4-chain) with extra pendant [b < e] (so by transitivity [a < e]).
    Element [e] is incomparable to [c] and [d].  Total 8 R-edges (the
    six chain edges plus [b < e] and [a < e]).  Incomparable pairs:
    [{e, c}], [{e, d}].

    2-realizer: [L1] orders [a < b < c < d < e];
    [L2] orders [a < b < e < c < d]. *)
Lemma n5_chain4_pendant_above_second_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 c d /\ R2 a c /\ R2 a d /\ R2 b d /\
     R2 b e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = b /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRcd [HRac [HRad [HRbd [HRbe HRae_HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct HRae_HR_only as [HRae HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, b=1, e=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxb Hye] | [Hxa Hye]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxb Hye] | [Hxa Hye]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRcd
            | exact HRac
            | exact HRad
            | exact HRbd
            | exact HRbe
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ce : L1 c e) by (unfold L1; rewrite Hrk1_c, Hrk1_e; lia).
      assert (HL2ce : L2 c e) by (rewrite <- Heq; exact HL1ce).
      unfold L2 in HL2ce. rewrite Hrk2_c, Hrk2_e in HL2ce. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-chain with pendant below the middle + isolated.

    Carrier [a, b, c, d, e] pairwise distinct.  Chain [a < b < c] with
    extra pendant [d < b] (so by transitivity [d < c]).  Element [e] is
    isolated.  Note: [a] and [d] are incomparable.  Total 5 R-edges:
    [a < b], [b < c], [a < c], [d < b], [d < c].  Incomparable pairs:
    [{a, d}], [{a, e}], [{b, e}], [{c, e}], [{d, e}].

    2-realizer: [L1] orders [a < d < b < c < e];
    [L2] orders [e < d < a < b < c]. *)
Lemma n5_chain3_pendant_middle_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 d b /\ R2 d c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = d /\ y = b) \/ (x = d /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRdb [HRdc HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, d=1, b=2, c=3, e=4.
     L2: e=0, d=1, a=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyb] | [Hxd Hyc]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyb] | [Hxd Hyc]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRdb
            | exact HRdc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 diamond with pendant below an intermediate node.

    Carrier [a, b, c, d, e] pairwise distinct.  Diamond with [a] bottom,
    [d] top, [b, c] intermediate (a<b, a<c, b<d, c<d, a<d).  Add pendant
    [e<b] (so by transitivity [e<d]; [e] is incomparable to both [a] and
    [c]).  Total 7 R-edges.  Incomparable pairs: {b,c}, {a,e}, {c,e}.

    2-realizer: [L1] orders [a < c < e < b < d];
    [L2] orders [e < a < b < c < d]. *)
Lemma n5_diamond_pendant_intermediate_below_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 a d /\ R2 e b /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/ (x = a /\ y = d) \/
         (x = e /\ y = b) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRad [HReb [HRed HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, e=2, b=3, d=4.
     L2: e=0, a=1, b=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] |
              [[Hxa Hyd] | [[Hxe Hyb] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] |
              [[Hxa Hyd] | [[Hxe Hyb] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRad
            | exact HReb
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ae : L1 a e) by (unfold L1; rewrite Hrk1_a, Hrk1_e; lia).
      assert (HL2ae : L2 a e) by (rewrite <- Heq; exact HL1ae).
      unfold L2 in HL2ae. rewrite Hrk2_a, Hrk2_e in HL2ae. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 diamond with pendant above an intermediate node.

    Carrier [a, b, c, d, e] pairwise distinct.  Diamond with [a] bottom,
    [d] top, [b, c] intermediate (a<b, a<c, b<d, c<d, a<d).  Add pendant
    [b<e] (so by transitivity [a<e]; [e] is incomparable to both [c] and
    [d]).  Total 7 R-edges.  Incomparable pairs: {b,c}, {c,e}, {d,e}.

    2-realizer: [L1] orders [a < c < b < d < e];
    [L2] orders [a < b < e < c < d]. *)
Lemma n5_diamond_pendant_intermediate_above_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 a d /\ R2 b e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/ (x = a /\ y = d) \/
         (x = b /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRad [HRbe [HRae HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, b=2, d=3, e=4.
     L2: a=0, b=1, e=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] |
              [[Hxa Hyd] | [[Hxb Hye] | [Hxa Hye]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] |
              [[Hxa Hyd] | [[Hxb Hye] | [Hxa Hye]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRad
            | exact HRbe
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1de : L1 d e) by (unfold L1; rewrite Hrk1_d, Hrk1_e; lia).
      assert (HL2de : L2 d e) by (rewrite <- Heq; exact HL1de).
      unfold L2 in HL2de. rewrite Hrk2_d, Hrk2_e in HL2de. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 two disjoint 3-chains sharing their top element.

    Carrier [a, b, c, d, e] pairwise distinct.  Chains [a<b<c] and
    [d<e<c] share the top [c].  Total 6 R-edges: [a<b, b<c, a<c, d<e,
    e<c, d<c].  Incomparable pairs: {a,d}, {a,e}, {b,d}, {b,e}.

    2-realizer: [L1] orders [a < b < d < e < c];
    [L2] orders [d < e < a < b < c]. *)
Lemma n5_3chain_chain_share_top_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 d e /\ R2 e c /\ R2 d c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = d /\ y = e) \/ (x = e /\ y = c) \/ (x = d /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRde [HRec [HRdc HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, d=2, e=3, c=4.
     L2: d=0, e=1, a=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxd Hye] | [[Hxe Hyc] | [Hxd Hyc]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxd Hye] | [[Hxe Hyc] | [Hxd Hyc]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRde
            | exact HRec
            | exact HRdc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 two disjoint 3-chains sharing their bottom element.

    Carrier [a, b, c, d, e] pairwise distinct.  Chains [a<b<c] and
    [a<d<e] share the bottom [a].  Total 6 R-edges: [a<b, b<c, a<c, a<d,
    d<e, a<e].  Incomparable pairs: {b,d}, {b,e}, {c,d}, {c,e}.

    2-realizer: [L1] orders [a < b < c < d < e];
    [L2] orders [a < d < e < b < c]. *)
Lemma n5_3chain_chain_share_bot_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 a d /\ R2 d e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = a /\ y = d) \/ (x = d /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRad [HRde [HRae HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, d=1, e=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxd Hye] | [Hxa Hye]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxd Hye] | [Hxa Hye]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRad
            | exact HRde
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bd : L1 b d) by (unfold L1; rewrite Hrk1_b, Hrk1_d; lia).
      assert (HL2bd : L2 b d) by (rewrite <- Heq; exact HL1bd).
      unfold L2 in HL2bd. rewrite Hrk2_b, Hrk2_d in HL2bd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-chain with pendant above the middle node + isolated.

    Carrier [a, b, c, d, e] pairwise distinct.  3-chain [a<b<c] with
    pendant [b<e] (so by transitivity [a<e]).  Element [d] is isolated.
    Total 5 R-edges.  Incomparable pairs: {a,d}, {b,d}, {c,d}, {d,e}
    and {c,e}.

    2-realizer: [L1] orders [d < a < b < e < c];
    [L2] orders [a < b < c < e < d]. *)
Lemma n5_chain3_pendant_above_middle_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 b e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = b /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRbe [HRae HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, a=1, b=2, e=3, c=4.
     L2: a=0, b=1, c=2, e=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxb Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] |
              [[Hxb Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRbe
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1da : L1 d a) by (unfold L1; rewrite Hrk1_d, Hrk1_a; lia).
      assert (HL2da : L2 d a) by (rewrite <- Heq; exact HL1da).
      unfold L2 in HL2da. rewrite Hrk2_d, Hrk2_a in HL2da. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-chain with pendant above the third element.

    Carrier [a, b, c, d, e] pairwise distinct.  Chain [a < b < c < d]
    (4-chain) with extra pendant [c < e] (so by transitivity [a < e]
    and [b < e]).  Element [e] is incomparable to [d].  Total 9 R-edges
    (the six chain edges plus [c < e], [a < e], [b < e]).  Incomparable
    pairs: [{e, d}].

    2-realizer: [L1] orders [a < b < c < e < d];
    [L2] orders [a < b < c < d < e]. *)
Lemma n5_chain4_pendant_above_third_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 c d /\ R2 a c /\ R2 a d /\ R2 b d /\
     R2 c e /\ R2 a e /\ R2 b e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = c /\ y = e) \/ (x = a /\ y = e) \/ (x = b /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRcd [HRac [HRad [HRbd [HRce [HRae HRbe_HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct HRbe_HR_only as [HRbe HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, e=3, d=4.
     L2: a=0, b=1, c=2, d=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxc Hye] | [[Hxa Hye] | [Hxb Hye]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxc Hye] | [[Hxa Hye] | [Hxb Hye]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRcd
            | exact HRac
            | exact HRad
            | exact HRbd
            | exact HRce
            | exact HRae
            | exact HRbe
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ed : L1 e d) by (unfold L1; rewrite Hrk1_e, Hrk1_d; lia).
      assert (HL2ed : L2 e d) by (rewrite <- Heq; exact HL1ed).
      unfold L2 in HL2ed. rewrite Hrk2_e, Hrk2_d in HL2ed. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 4-chain with pendant below the second element.

    Carrier [a, b, c, d, e] pairwise distinct.  Chain [a < b < c < d]
    (4-chain) with extra pendant [e < b] (so by transitivity [e < c]
    and [e < d]).  Element [e] is incomparable to [a].  Total 9 R-edges
    (the six chain edges plus [e < b], [e < c], [e < d]).  Incomparable
    pairs: [{a, e}].

    2-realizer: [L1] orders [e < a < b < c < d];
    [L2] orders [a < e < b < c < d]. *)
Lemma n5_chain4_pendant_below_second_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 c d /\ R2 a c /\ R2 a d /\ R2 b d /\
     R2 e b /\ R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = e /\ y = b) \/ (x = e /\ y = c) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRcd [HRac [HRad [HRbd [HReb [HRec HRed_HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct HRed_HR_only as [HRed HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, a=1, b=2, c=3, d=4.
     L2: a=0, e=1, b=2, c=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxa Hyc] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRcd
            | exact HRac
            | exact HRad
            | exact HRbd
            | exact HReb
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ea : L1 e a) by (unfold L1; rewrite Hrk1_e, Hrk1_a; lia).
      assert (HL2ea : L2 e a) by (rewrite <- Heq; exact HL1ea).
      unfold L2 in HL2ea. rewrite Hrk2_e, Hrk2_a in HL2ea. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 V-shape with chain extending below the apex.

    Carrier [a, b, c, d, e] pairwise distinct.  V-shape [a < b], [a < c]
    (apex [a]) extended by chain [e < d < a] (so by transitivity
    [d < b], [d < c], [e < a], [e < b], [e < c]).  Elements [b] and [c]
    are incomparable.  Total 9 R-edges:
    [a < b], [a < c], [d < a], [e < d], [d < b], [d < c],
    [e < a], [e < b], [e < c].  Incomparable pairs: [{b, c}].

    2-realizer: [L1] orders [e < d < a < b < c];
    [L2] orders [e < d < a < c < b]. *)
Lemma n5_V_with_chain_below_apex_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 d a /\ R2 e d /\
     R2 d b /\ R2 d c /\ R2 e a /\ R2 e b /\ R2 e c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = d /\ y = a) \/
         (x = e /\ y = d) \/ (x = d /\ y = b) \/ (x = d /\ y = c) \/
         (x = e /\ y = a) \/ (x = e /\ y = b) \/ (x = e /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRda [HRed [HRdb [HRdc [HRea [HReb HRec_HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct HRec_HR_only as [HRec HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, a=2, b=3, c=4.
     L2: e=0, d=1, a=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxd Hya] | [[Hxe Hyd] |
              [[Hxd Hyb] | [[Hxd Hyc] | [[Hxe Hya] | [[Hxe Hyb] | [Hxe Hyc]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxd Hya] | [[Hxe Hyd] |
              [[Hxd Hyb] | [[Hxd Hyc] | [[Hxe Hya] | [[Hxe Hyb] | [Hxe Hyc]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRda
            | exact HRed
            | exact HRdb
            | exact HRdc
            | exact HRea
            | exact HReb
            | exact HRec
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-V-shape with chain extending above the apex.

    Carrier [a, b, c, d, e] pairwise distinct.  Inv-V-shape [a < c],
    [b < c] (apex [c]) extended by chain [c < d < e] (so by transitivity
    [a < d], [b < d], [a < e], [b < e], [c < e]).  Elements [a] and [b]
    are incomparable.  Total 9 R-edges:
    [a < c], [b < c], [c < d], [d < e], [a < d], [b < d],
    [a < e], [b < e], [c < e].  Incomparable pairs: [{a, b}].

    2-realizer: [L1] orders [a < b < c < d < e];
    [L2] orders [b < a < c < d < e]. *)
Lemma n5_inv_V_with_chain_above_apex_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 b c /\ R2 c d /\ R2 d e /\
     R2 a d /\ R2 b d /\ R2 a e /\ R2 b e /\ R2 c e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = b /\ y = c) \/ (x = c /\ y = d) \/
         (x = d /\ y = e) \/ (x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = a /\ y = e) \/ (x = b /\ y = e) \/ (x = c /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRbc [HRcd [HRde [HRad [HRbd [HRae [HRbe HRce_HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct HRce_HR_only as [HRce HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: b=0, a=1, c=2, d=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxd Hye] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxa Hye] | [[Hxb Hye] | [Hxc Hye]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxc Hyd] | [[Hxd Hye] |
              [[Hxa Hyd] | [[Hxb Hyd] | [[Hxa Hye] | [[Hxb Hye] | [Hxc Hye]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRbc
            | exact HRcd
            | exact HRde
            | exact HRad
            | exact HRbd
            | exact HRae
            | exact HRbe
            | exact HRce
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 two 3-chains sharing the middle element.

    Carrier [a, b, c, d, e] pairwise distinct.  Chain [a < b < c] and
    chain [d < b < e] share the middle [b].  By transitivity also
    [a < e] (via [a < b < e]) and [d < c] (via [d < b < c]).
    Elements [a] and [d] are incomparable, and elements [c] and [e]
    are incomparable.  Total 8 R-edges:
    [a < b], [b < c], [a < c], [d < b], [b < e], [d < e],
    [a < e], [d < c].  Incomparable pairs: [{a, d}], [{c, e}].

    2-realizer: [L1] orders [a < d < b < c < e];
    [L2] orders [d < a < b < e < c]. *)
Lemma n5_two_3chains_share_middle_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 d b /\ R2 b e /\ R2 d e /\
     R2 a e /\ R2 d c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = d /\ y = b) \/ (x = b /\ y = e) \/ (x = d /\ y = e) \/
         (x = a /\ y = e) \/ (x = d /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRdb [HRbe [HRde [HRae HRdc_HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct HRdc_HR_only as [HRdc HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, d=1, b=2, c=3, e=4.
     L2: d=0, a=1, b=2, e=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyb] |
              [[Hxb Hye] | [[Hxd Hye] | [[Hxa Hye] | [Hxd Hyc]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyb] |
              [[Hxb Hye] | [[Hxd Hye] | [[Hxa Hye] | [Hxd Hyc]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRdb
            | exact HRbe
            | exact HRde
            | exact HRae
            | exact HRdc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-up with two leaves sharing a common top element.

    Carrier [a, b, c, d, e] pairwise distinct.  3-claw-up [a < b],
    [a < c], [a < d] (apex [a]) with additional edges [b < e], [c < e]
    so that two of the three leaves [b, c] share a common top [e].
    By transitivity also [a < e].  Element [d] is incomparable to
    [b, c, e].  Total 6 R-edges:
    [a < b], [a < c], [a < d], [b < e], [c < e], [a < e].
    Incomparable pairs: [{b, c}], [{b, d}], [{c, d}], [{d, e}].

    2-realizer: [L1] orders [a < b < c < e < d];
    [L2] orders [a < d < c < b < e]. *)
Lemma n5_3claw_up_two_leaves_share_top_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 b e /\ R2 c e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = e) \/ (x = c /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRbe [HRce HRae_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRae_HR_only as [HRae HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, e=3, d=4.
     L2: a=0, d=1, c=2, b=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hye] |
              [[Hxc Hye] | [Hxa Hye]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hye] |
              [[Hxc Hye] | [Hxa Hye]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRbe
            | exact HRce
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** n=5 sub-case: 3-claw-down with two leaves sharing a common bottom.

    Shape (6 edges): [d] is the top (sink); [a, b, c] are three leaves
    below [d] (edges [a<d], [b<d], [c<d]); [e] is a common bottom for
    [b] and [c] (edges [e<b], [e<c]), with [e<d] by transitivity.

    The dual of [n5_3claw_up_two_leaves_share_top_two_realizer]:
    invert direction and rename so the structure is symmetric to the
    primal lemma (a, b, c remain leaves but at the bottom of [d]; e
    plays the role of the shared bottom analogous to the shared top).

    Explicit 2-realizer (rank-encoded):
    - L1: e < b < c < a < d.
    - L2: a < e < c < b < d.
    Both extend [R2] on the six edges, and their intersection on
    off-diagonal pairs is exactly [R2] (every non-edge has L1, L2 in
    opposite orientations). *)
Lemma n5_3claw_down_two_leaves_share_bot_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a d /\ R2 b d /\ R2 c d /\ R2 e b /\ R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = d) \/ (x = b /\ y = d) \/ (x = c /\ y = d) \/
         (x = e /\ y = b) \/ (x = e /\ y = c) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRad [HRbd [HRcd [HReb [HRec HRed_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRed_HR_only as [HRed HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, b=1, c=2, a=3, d=4.
     L2: a=0, e=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyd] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxe Hyb] |
              [[Hxe Hyc] | [Hxe Hyd]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyd] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxe Hyb] |
              [[Hxe Hyc] | [Hxe Hyd]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRad
            | exact HRbd
            | exact HRcd
            | exact HReb
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1be : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2be : L2 b c) by (rewrite <- Heq; exact HL1be).
      unfold L2 in HL2be. rewrite Hrk2_b, Hrk2_c in HL2be. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** n=5 sub-case: 3-chain + top pendant extended by a chain below it.

    Shape (6 edges): the 3-chain [a < b < c]; a pendant [d < c]
    attached to the top of the chain; and a chain [e < d] extending
    the pendant downward, giving [e < c] by transitivity.

    Concretely: [a, e] are minimal; [d, b] are intermediate
    (incomparable to each other); [c] is the unique maximum.

    Explicit 2-realizer (rank-encoded):
    - L1: e < d < a < b < c.
    - L2: a < b < e < d < c.

    Together they cover all six edges; their intersection on
    off-diagonal pairs is exactly [R2] (every non-edge has L1 and L2
    disagreeing on orientation). *)
Lemma n5_chain3_top_pendant_with_chain_below_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 d c /\ R2 e d /\ R2 e c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = d /\ y = c) \/ (x = e /\ y = d) \/ (x = e /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRdc [HRed HRec_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRec_HR_only as [HRec HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, a=2, b=3, c=4.
     L2: a=0, b=1, e=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyc] |
              [[Hxe Hyd] | [Hxe Hyc]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyc] |
              [[Hxe Hyd] | [Hxe Hyc]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRdc
            | exact HRed
            | exact HRec
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1da : L1 d a) by (unfold L1; rewrite Hrk1_d, Hrk1_a; lia).
      assert (HL2da : L2 d a) by (rewrite <- Heq; exact HL1da).
      unfold L2 in HL2da. rewrite Hrk2_d, Hrk2_a in HL2da. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** n=5 sub-case: 3-chain + bot pendant extended by a chain above it.

    Shape (6 edges): the 3-chain [a < b < c]; a pendant [a < d]
    attached to the bottom of the chain; and a chain [d < e] extending
    the pendant upward, giving [a < e] by transitivity.

    Concretely: [a] is the unique minimum; [b, d] are intermediate
    (incomparable to each other); [c, e] are two distinct maxima.
    Dual of [n5_chain3_top_pendant_with_chain_below_two_realizer].

    Explicit 2-realizer (rank-encoded):
    - L1: a < b < c < d < e.
    - L2: a < d < e < b < c.

    Together they cover all six edges; their intersection on
    off-diagonal pairs is exactly [R2]. *)
Lemma n5_chain3_bot_pendant_with_chain_above_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 a d /\ R2 d e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = a /\ y = d) \/ (x = d /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRad [HRde HRae_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRae_HR_only as [HRae HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, d=1, e=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxd Hye] | [Hxa Hye]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxa Hyd] |
              [[Hxd Hye] | [Hxa Hye]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRad
            | exact HRde
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bd : L1 b d) by (unfold L1; rewrite Hrk1_b, Hrk1_d; lia).
      assert (HL2bd : L2 b d) by (rewrite <- Heq; exact HL1bd).
      unfold L2 in HL2bd. rewrite Hrk2_b, Hrk2_d in HL2bd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** n=5 sub-case: inverse-T-shape extended (dual of T-shape extended).

    Shape (6 edges): a chain [c < b < a] (the spine of an inverted T,
    with [a] at the top); an extra branch [d < b, d < a] making [d] a
    second bottom below the intermediate [b]; and a pendant [d < e]
    above [d] giving [e] as an alternative maximum.

    Concretely: minima [{c, d}], top maximum [a], top maximum [e],
    intermediate [b].  This is the order dual of
    [n5_T_shape_extended_two_realizer].

    Explicit 2-realizer (rank-encoded):
    - L1: d < e < c < b < a.
    - L2: c < d < b < a < e.

    All six edges are extended by both linear orders, and every
    non-edge has the two ranks disagreeing on orientation. *)
Lemma n5_inv_T_shape_extended_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c b /\ R2 b a /\ R2 c a /\ R2 d b /\ R2 d a /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = b) \/ (x = b /\ y = a) \/ (x = c /\ y = a) \/
         (x = d /\ y = b) \/ (x = d /\ y = a) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRcb [HRba [HRca [HRdb [HRda HRde_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRde_HR_only as [HRde HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, e=1, c=2, b=3, a=4.
     L2: c=0, d=1, b=2, a=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hyb] |
              [[Hxd Hya] | [Hxd Hye]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hyb] |
              [[Hxd Hya] | [Hxd Hye]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRcb
            | exact HRba
            | exact HRca
            | exact HRdb
            | exact HRda
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ec : L1 e c) by (unfold L1; rewrite Hrk1_e, Hrk1_c; lia).
      assert (HL2ec : L2 e c) by (rewrite <- Heq; exact HL1ec).
      unfold L2 in HL2ec. rewrite Hrk2_e, Hrk2_c in HL2ec. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** n=5 sub-case: 2-chain with a 3-claw at the top (fan-up shape).

    Shape (7 edges): a stem [a < b] at the bottom; from [b] a 3-claw
    upward to [c, d, e] (edges [b < c], [b < d], [b < e]); the
    transitive closures [a < c], [a < d], [a < e].

    Concretely: [a] minimum, [b] intermediate, [c, d, e] three
    pairwise incomparable maxima all covered by [b].  Distinct from
    [n5_Y_up_pendant_above_two_realizer], which adds the pendant ABOVE
    one of the existing branches rather than sharing level with them.

    Explicit 2-realizer (rank-encoded):
    - L1: a < b < c < d < e.
    - L2: a < b < e < d < c.

    Both linear orders extend the seven edges, and the three
    incomparable maxima [c, d, e] appear in opposite cyclic orderings
    in L1 vs L2 — so their pairwise non-edges are excluded from the
    intersection. *)
Lemma n5_chain2_plus_3claw_top_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 b d /\ R2 b e /\
     R2 a c /\ R2 a d /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = b /\ y = d) \/
         (x = b /\ y = e) \/
         (x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRbd [HRbe [HRac [HRad HRae_HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct HRae_HR_only as [HRae HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, b=1, e=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] | [[Hxb Hye] |
              [[Hxa Hyc] | [[Hxa Hyd] | [Hxa Hye]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxb Hyd] | [[Hxb Hye] |
              [[Hxa Hyc] | [[Hxa Hyd] | [Hxa Hye]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRbd
            | exact HRbe
            | exact HRac
            | exact HRad
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** n=5 sub-case: 3-claw at the bottom with a 2-chain on top (fan-down).

    Shape (7 edges): three leaves [c, d, e] below [a] (edges [c < a],
    [d < a], [e < a]); a stem [a < b] above [a]; and the transitive
    closures [c < b], [d < b], [e < b].

    Concretely: [c, d, e] three minima, [a] intermediate, [b] unique
    maximum.  Order dual of [n5_chain2_plus_3claw_top_two_realizer].

    Explicit 2-realizer (rank-encoded):
    - L1: c < d < e < a < b.
    - L2: e < d < c < a < b.

    Both linear orders extend the seven edges; the three minima
    [c, d, e] appear in opposite orderings in L1 vs L2, so their
    pairwise non-edges are excluded from the intersection. *)
Lemma n5_chain2_plus_3claw_bot_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c a /\ R2 d a /\ R2 e a /\ R2 a b /\
     R2 c b /\ R2 d b /\ R2 e b /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = a) \/ (x = d /\ y = a) \/ (x = e /\ y = a) \/
         (x = a /\ y = b) \/
         (x = c /\ y = b) \/ (x = d /\ y = b) \/ (x = e /\ y = b)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRca [HRda [HRea [HRab [HRcb [HRdb HReb_HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct HReb_HR_only as [HReb HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: c=0, d=1, e=2, a=3, b=4.
     L2: e=0, d=1, c=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_c : rk1 c = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxd Hya] | [[Hxe Hya] | [[Hxa Hyb] |
              [[Hxc Hyb] | [[Hxd Hyb] | [Hxe Hyb]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxd Hya] | [[Hxe Hya] | [[Hxa Hyb] |
              [[Hxc Hyb] | [[Hxd Hyb] | [Hxe Hyb]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRca
            | exact HRda
            | exact HRea
            | exact HRab
            | exact HRcb
            | exact HRdb
            | exact HReb
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-up with chain extending below the apex.

    Carrier [a, b, c, d, e] pairwise distinct.  3-claw-up at apex [a]
    with three leaves [b], [c], [d] (so [a < b], [a < c], [a < d]) plus
    a pendant [e < a] below the apex (so by transitivity [e < b],
    [e < c], [e < d]).  Leaves [b], [c], [d] are pairwise incomparable.
    Total 7 R-edges:
    [a < b], [a < c], [a < d], [e < a], [e < b], [e < c], [e < d].
    Incomparable pairs: [{b, c}], [{b, d}], [{c, d}].

    2-realizer: [L1] orders [e < a < b < c < d]; [L2] orders
    [e < a < d < c < b].  The two leaf orderings are reverses of each
    other on {b, c, d}, so every incomparable pair among the leaves is
    flipped between [L1] and [L2]. *)
Lemma n5_3claw_up_chain_below_apex_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 e a /\
     R2 e b /\ R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = e /\ y = a) \/
         (x = e /\ y = b) \/ (x = e /\ y = c) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRea [HReb [HRec HRed_HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct HRed_HR_only as [HRed HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, a=1, b=2, c=3, d=4.
     L2: e=0, a=1, d=2, c=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxe Hya] |
              [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxe Hya] |
              [[Hxe Hyb] | [[Hxe Hyc] | [Hxe Hyd]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRea
            | exact HReb
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bd : L1 b d) by (unfold L1; rewrite Hrk1_b, Hrk1_d; lia).
      assert (HL2bd : L2 b d) by (rewrite <- Heq; exact HL1bd).
      unfold L2 in HL2bd. rewrite Hrk2_b, Hrk2_d in HL2bd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-down with chain extending above the apex.

    Carrier [a, b, c, d, e] pairwise distinct.  3-claw-down at apex [a]
    with three leaves [b], [c], [d] (so [b < a], [c < a], [d < a]) plus
    a pendant [a < e] above the apex (so by transitivity [b < e],
    [c < e], [d < e]).  Leaves [b], [c], [d] are pairwise incomparable.
    Total 7 R-edges:
    [b < a], [c < a], [d < a], [a < e], [b < e], [c < e], [d < e].
    Incomparable pairs: [{b, c}], [{b, d}], [{c, d}].

    2-realizer: [L1] orders [b < c < d < a < e]; [L2] orders
    [d < c < b < a < e].  The two leaf orderings are reverses of each
    other on {b, c, d}. *)
Lemma n5_3claw_down_chain_above_apex_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 c a /\ R2 d a /\ R2 a e /\
     R2 b e /\ R2 c e /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = c /\ y = a) \/ (x = d /\ y = a) \/
         (x = a /\ y = e) \/
         (x = b /\ y = e) \/ (x = c /\ y = e) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRca [HRda [HRae [HRbe [HRce HRde_HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct HRde_HR_only as [HRde HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, c=1, d=2, a=3, e=4.
     L2: d=0, c=1, b=2, a=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [[Hxa Hye] |
              [[Hxb Hye] | [[Hxc Hye] | [Hxd Hye]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [[Hxa Hye] |
              [[Hxb Hye] | [[Hxc Hye] | [Hxd Hye]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRca
            | exact HRda
            | exact HRae
            | exact HRbe
            | exact HRce
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bd : L1 b d) by (unfold L1; rewrite Hrk1_b, Hrk1_d; lia).
      assert (HL2bd : L2 b d) by (rewrite <- Heq; exact HL1bd).
      unfold L2 in HL2bd. rewrite Hrk2_b, Hrk2_d in HL2bd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 N-shape with bottom-extension on one chain.

    Carrier [a, b, c, d, e] pairwise distinct.  N-shape on {a, b, c, d}:
    [a < b], [c < b], [c < d].  Extra element [e] sits below [a], so
    [e < a] (and transitively [e < b]).  No other relations.  Total 5
    R-edges:  [a < b], [c < b], [c < d], [e < a], [e < b].
    Incomparable pairs: [{a, c}], [{a, d}], [{b, d}], [{c, e}], [{d, e}].

    2-realizer:
      [L1] orders [c < d < e < a < b];
      [L2] orders [e < a < c < b < d].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_N_plus_bottom_extension_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 e a /\ R2 e b /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
         (x = e /\ y = a) \/ (x = e /\ y = b)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd [HRea HReb_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HReb_HR_only as [HReb HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: c=0, d=1, e=2, a=3, b=4.
     L2: e=0, a=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_c : rk1 c = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxe Hya] | [Hxe Hyb]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxe Hya] | [Hxe Hyb]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRea
            | exact HReb
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ca : L1 c a) by (unfold L1; rewrite Hrk1_c, Hrk1_a; lia).
      assert (HL2ca : L2 c a) by (rewrite <- Heq; exact HL1ca).
      unfold L2 in HL2ca. rewrite Hrk2_c, Hrk2_a in HL2ca. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 N-shape with top-pendant on left chain.

    Carrier [a, b, c, d, e] pairwise distinct.  N-shape on {a, b, c, d}:
    [a < b], [c < b], [c < d].  Extra element [e] sits above [a] only,
    so [a < e].  No other relations.  Total 4 R-edges:
    [a < b], [c < b], [c < d], [a < e].
    Incomparable pairs: [{a, c}], [{a, d}], [{b, d}], [{b, e}],
    [{c, e}], [{d, e}].

    2-realizer:
      [L1] orders [c < d < a < b < e];
      [L2] orders [a < e < c < b < d].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_N_plus_top_pendant_on_left_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
         (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd HRae_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRae_HR_only as [HRae HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: c=0, d=1, a=2, b=3, e=4.
     L2: a=0, e=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_c : rk1 c = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [Hxa Hye]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [Hxa Hye]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ca : L1 c a) by (unfold L1; rewrite Hrk1_c, Hrk1_a; lia).
      assert (HL2ca : L2 c a) by (rewrite <- Heq; exact HL1ca).
      unfold L2 in HL2ca. rewrite Hrk2_c, Hrk2_a in HL2ca. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-up at apex [c] with extra pendant at one leaf.

    Carrier [a, b, c, d, e] pairwise distinct.  3-claw-up with apex
    [c] going to leaves [b], [d], [e] ([c < b], [c < d], [c < e]).
    Extra element [a] sits below the leaf [b] only ([a < b]).  No
    other relations.  Total 4 R-edges:
    [a < b], [c < b], [c < d], [c < e].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}],
    [{b, e}], [{d, e}].

    2-realizer:
      [L1] orders [a < c < b < d < e];
      [L2] orders [c < e < d < a < b].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_3claw_up_pendant_at_one_leaf_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 c e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
         (x = c /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd HRce_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRce_HR_only as [HRce HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, b=2, d=3, e=4.
     L2: c=0, e=1, d=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [Hxc Hye]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [Hxc Hye]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRce
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 complete bipartite K_{3,2} with two bottoms and three tops.

    Carrier [a, b, c, d, e] pairwise distinct.  Elements [c, e] form the
    bottom antichain and [a, b, d] form the top antichain; every bottom
    is below every top.  Total 6 R-edges: [c < a], [c < b], [c < d],
    [e < a], [e < b], [e < d].
    Incomparable pairs: [{a, b}], [{a, d}], [{b, d}], [{c, e}].

    2-realizer (dual of [n5_K_2_3_two_realizer]):
      [L1] orders [c < e < a < b < d];
      [L2] orders [e < c < d < b < a].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_K_3_2_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c a /\ R2 c b /\ R2 c d /\ R2 e a /\ R2 e b /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = a) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
         (x = e /\ y = a) \/ (x = e /\ y = b) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRca [HRcb [HRcd [HRea [HReb HRed_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRed_HR_only as [HRed HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: c=0, e=1, a=2, b=3, d=4.
     L2: e=0, c=1, d=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_c : rk1 c = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = c)) as [Hdc|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [Hde'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [Hda'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [Hdb'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxc Hyd] |
              [[Hxe Hya] | [[Hxe Hyb] | [Hxe Hyd]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxc Hyd] |
              [[Hxe Hya] | [[Hxe Hyb] | [Hxe Hyd]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRca
            | exact HRcb
            | exact HRcd
            | exact HRea
            | exact HReb
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ce : L1 c e) by (unfold L1; rewrite Hrk1_c, Hrk1_e; lia).
      assert (HL2ce : L2 c e) by (rewrite <- Heq; exact HL1ce).
      unfold L2 in HL2ce. rewrite Hrk2_c, Hrk2_e in HL2ce. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 complete bipartite K_{2,3} with three bottoms and two tops.

    Carrier [a, b, c, d, e] pairwise distinct.  Elements [a, b] form the
    top antichain and [c, d, e] form the bottom antichain; every bottom
    is below every top.  Total 6 R-edges: [c < a], [c < b], [d < a],
    [d < b], [e < a], [e < b].
    Incomparable pairs: [{a, b}], [{c, d}], [{c, e}], [{d, e}].

    2-realizer:
      [L1] orders [c < d < e < a < b];
      [L2] orders [e < d < c < b < a].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_K_2_3_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c a /\ R2 c b /\ R2 d a /\ R2 d b /\ R2 e a /\ R2 e b /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = a) \/ (x = c /\ y = b) \/
         (x = d /\ y = a) \/ (x = d /\ y = b) \/
         (x = e /\ y = a) \/ (x = e /\ y = b)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRca [HRcb [HRda [HRdb [HRea HReb_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HReb_HR_only as [HReb HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: c=0, d=1, e=2, a=3, b=4.
     L2: e=0, d=1, c=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_c : rk1 c = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] |
              [[Hxd Hyb] | [[Hxe Hya] | [Hxe Hyb]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] |
              [[Hxd Hyb] | [[Hxe Hya] | [Hxe Hyb]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRca
            | exact HRcb
            | exact HRda
            | exact HRdb
            | exact HRea
            | exact HReb
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-up at [b] with extra parent [d] at one child [c].

    Carrier [a, b, c, d, e] pairwise distinct.  Element [b] has three
    children [a], [c], [e].  Element [c] also has another parent [d]
    (in addition to its parent [b]).  No other relations.  Total 4
    R-edges: [b < a], [b < c], [b < e], [d < c].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}],
    [{c, e}], [{d, e}].

    2-realizer (dual of [n5_3claw_down_extra_leaf_two_realizer]):
      [L1] orders [b < e < a < d < c];
      [L2] orders [d < b < c < a < e].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_3claw_up_extra_parent_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 b e /\ R2 d c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = b /\ y = e) \/
         (x = d /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRbe HRdc_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRdc_HR_only as [HRdc HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, e=1, a=2, d=3, c=4.
     L2: d=0, b=1, c=2, a=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxb Hye] | [Hxd Hyc]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxb Hye] | [Hxd Hyc]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRbe
            | exact HRdc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 a d) by (unfold L1; rewrite Hrk1_a, Hrk1_d; lia).
      assert (HL2ad : L2 a d) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_a, Hrk2_d in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-down at [b] with extra child [d] at one parent [c].

    Carrier [a, b, c, d, e] pairwise distinct.  Element [b] has three
    parents [a], [c], [e].  Element [c] also has another child [d]
    (in addition to its child [b]).  No other relations.  Total 4
    R-edges: [a < b], [c < b], [e < b], [c < d].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}],
    [{c, e}], [{d, e}].

    2-realizer:
      [L1] orders [c < d < a < e < b];
      [L2] orders [e < a < c < b < d].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_3claw_down_extra_leaf_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 e b /\ R2 c d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = e /\ y = b) \/
         (x = c /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HReb HRcd_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRcd_HR_only as [HRcd HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: c=0, d=1, a=2, e=3, b=4.
     L2: e=0, a=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_c : rk1 c = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxe Hyb] | [Hxc Hyd]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxe Hyb] | [Hxc Hyd]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HReb
            | exact HRcd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1da : L1 d a) by (unfold L1; rewrite Hrk1_d, Hrk1_a; lia).
      assert (HL2da : L2 d a) by (rewrite <- Heq; exact HL1da).
      unfold L2 in HL2da. rewrite Hrk2_d, Hrk2_a in HL2da. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-N-shape extended by a pendant edge from one leaf.

    Carrier [a, b, c, d, e] pairwise distinct.  inv-N-shape:
    [b < a], [b < c], [d < c].  Pendant edge [e < d], with transitive
    edge [e < c].  No other strict edges.  Total 5 R-edges:
    [b < a], [b < c], [d < c], [e < d], [e < c].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}], [{b, e}].

    2-realizer (dual of [n5_N_plus_pendant_two_realizer]):
      [L1] orders [e < d < b < c < a];
      [L2] orders [b < a < e < d < c].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_inv_N_plus_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 e d /\ R2 e c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/
         (x = d /\ y = c) \/ (x = e /\ y = d) \/ (x = e /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc [HRed HRec_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HRec_HR_only as [HRec HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, b=2, c=3, a=4.
     L2: b=0, a=1, e=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxe Hyd] | [Hxe Hyc]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxe Hyd] | [Hxe Hyc]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRed
            | exact HRec
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ca : L1 c a) by (unfold L1; rewrite Hrk1_c, Hrk1_a; lia).
      assert (HL2ca : L2 c a) by (rewrite <- Heq; exact HL1ca).
      unfold L2 in HL2ca. rewrite Hrk2_c, Hrk2_a in HL2ca. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 Y-down shape with pendant above the top.

    Carrier [a, b, c, d, e] pairwise distinct.  Y-down shape: [c < b],
    [d < b], [b < a], plus transitives [c < a], [d < a].  Pendant above
    the top: [a < e], with transitives [b < e], [c < e], [d < e].  Total
    9 R-edges.  Incomparable pairs: [{c, d}].

    2-realizer (dual of [n5_Y_up_pendant_below_two_realizer]):
      [L1] orders [d < c < b < a < e];
      [L2] orders [c < d < b < a < e].
    The single incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_Y_down_pendant_above_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c b /\ R2 d b /\ R2 b a /\ R2 c a /\ R2 d a /\
     R2 a e /\ R2 b e /\ R2 c e /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = b) \/ (x = d /\ y = b) \/ (x = b /\ y = a) \/
         (x = c /\ y = a) \/ (x = d /\ y = a) \/
         (x = a /\ y = e) \/ (x = b /\ y = e) \/ (x = c /\ y = e) \/
         (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRcb [HRdb [HRba [HRca [HRda
       [HRae [HRbe [HRce HRde_HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct HRde_HR_only as [HRde HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, c=1, b=2, a=3, e=4.
     L2: c=0, d=1, b=2, a=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxd Hyb] | [[Hxb Hya] |
              [[Hxc Hya] | [[Hxd Hya] |
              [[Hxa Hye] | [[Hxb Hye] | [[Hxc Hye] | [Hxd Hye]]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hyb] | [[Hxd Hyb] | [[Hxb Hya] |
              [[Hxc Hya] | [[Hxd Hya] |
              [[Hxa Hye] | [[Hxb Hye] | [[Hxc Hye] | [Hxd Hye]]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRcb
            | exact HRdb
            | exact HRba
            | exact HRca
            | exact HRda
            | exact HRae
            | exact HRbe
            | exact HRce
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1dc : L1 d c) by (unfold L1; rewrite Hrk1_d, Hrk1_c; lia).
      assert (HL2dc : L2 d c) by (rewrite <- Heq; exact HL1dc).
      unfold L2 in HL2dc. rewrite Hrk2_d, Hrk2_c in HL2dc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-N-shape with top-extension on one chain.

    Carrier [a, b, c, d, e] pairwise distinct.  inv-N-shape on
    {a, b, c, d}: [b < a], [b < c], [d < c].  Extra element [e] sits
    above [a], so [a < e] (and transitively [b < e]).  No other
    relations.  Total 5 R-edges:
    [b < a], [b < c], [d < c], [a < e], [b < e].
    Incomparable pairs: [{a, c}], [{a, d}], [{b, d}], [{c, e}], [{d, e}].

    2-realizer (dual of [n5_N_plus_bottom_extension_two_realizer]):
      [L1] orders [b < a < e < d < c];
      [L2] orders [d < b < c < a < e].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_inv_N_plus_top_extension_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 a e /\ R2 b e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
         (x = a /\ y = e) \/ (x = b /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc [HRae HRbe_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HRbe_HR_only as [HRbe HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, a=1, e=2, d=3, c=4.
     L2: d=0, b=1, c=2, a=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxa Hye] | [Hxb Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxa Hye] | [Hxb Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRae
            | exact HRbe
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-claw-down at apex [c] with extra pendant at one leaf.

    Carrier [a, b, c, d, e] pairwise distinct.  3-claw-down with apex
    [c] gathering leaves [b], [d], [e] ([b < c], [d < c], [e < c]).
    Extra element [a] sits above the leaf [b] only ([b < a]).  No
    other relations.  Total 4 R-edges:
    [b < a], [b < c], [d < c], [e < c].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}],
    [{b, e}], [{d, e}].

    2-realizer (dual of [n5_3claw_up_pendant_at_one_leaf_two_realizer]):
      [L1] orders [e < d < b < c < a];
      [L2] orders [b < a < d < e < c].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_3claw_down_pendant_at_one_leaf_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 e c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
         (x = e /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc HRec_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRec_HR_only as [HRec HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, b=2, c=3, a=4.
     L2: b=0, a=1, d=2, e=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxe Hyc]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxe Hyc]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRec
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ca : L1 c a) by (unfold L1; rewrite Hrk1_c, Hrk1_a; lia).
      assert (HL2ca : L2 c a) by (rewrite <- Heq; exact HL1ca).
      unfold L2 in HL2ca. rewrite Hrk2_c, Hrk2_a in HL2ca. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-N-shape with bot-pendant on left chain.

    Carrier [a, b, c, d, e] pairwise distinct.  inv-N-shape on
    {a, b, c, d}: [b < a], [b < c], [d < c].  Extra element [e] sits
    below [a] only, so [e < a].  No other relations.  Total 4 R-edges:
    [b < a], [b < c], [d < c], [e < a].
    Incomparable pairs: [{a, c}], [{a, d}], [{b, d}], [{b, e}],
    [{c, e}], [{d, e}].

    2-realizer (dual of [n5_N_plus_top_pendant_on_left_two_realizer]):
      [L1] orders [e < b < a < d < c];
      [L2] orders [d < b < c < e < a].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_inv_N_plus_bot_pendant_on_left_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 e a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
         (x = e /\ y = a)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc HRea_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRea_HR_only as [HRea HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, b=1, a=2, d=3, c=4.
     L2: d=0, b=1, c=2, e=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxe Hya]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [Hxe Hya]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRea
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 N-shape with top pendant on the right chain.

    Carrier [a, b, c, d, e] pairwise distinct.  N-shape with [a < b],
    [c < b], [c < d].  Element [e] sits above [d] only ([d < e]),
    which transitively gives [c < e].  Total 5 R-edges:
    [a < b], [c < b], [c < d], [d < e], [c < e].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}], [{b, e}].

    2-realizer:
      [L1] orders [a < c < b < d < e];
      [L2] orders [c < d < e < a < b].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_N_plus_top_pendant_on_right_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 d e /\ R2 c e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
         (x = d /\ y = e) \/ (x = c /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd [HRde HRce_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HRce_HR_only as [HRce HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, b=2, d=3, e=4.
     L2: c=0, d=1, e=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxd Hye] | [Hxc Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxd Hye] | [Hxc Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRde
            | exact HRce
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 N-shape with bottom pendant on the right (c-fork) chain.

    Carrier [a, b, c, d, e] pairwise distinct.  N-shape with [a < b],
    [c < b], [c < d].  Element [e] sits below [c] only ([e < c]),
    which transitively gives [e < b] and [e < d].  Total 6 R-edges:
    [a < b], [c < b], [c < d], [e < c], [e < b], [e < d].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}].

    2-realizer:
      [L1] orders [a < e < c < b < d];
      [L2] orders [e < c < d < a < b].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_N_plus_bot_pendant_on_right_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 e c /\ R2 e b /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
         (x = e /\ y = c) \/ (x = e /\ y = b) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd [HRec [HReb HRed_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRed_HR_only as [HRed HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, e=1, c=2, b=3, d=4.
     L2: e=0, c=1, d=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxe Hyc] | [[Hxe Hyb] | [Hxe Hyd]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxe Hyc] | [[Hxe Hyb] | [Hxe Hyd]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRec
            | exact HReb
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-N-shape with top pendant on the right (c-fork) chain.

    Carrier [a, b, c, d, e] pairwise distinct.  inv-N-shape with
    [b < a], [b < c], [d < c].  Element [e] sits above [c] only
    ([c < e]), which transitively gives [b < e] and [d < e].  Total 6
    R-edges:
    [b < a], [b < c], [d < c], [c < e], [b < e], [d < e].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}].

    2-realizer:
      [L1] orders [b < a < d < c < e];
      [L2] orders [d < b < c < e < a].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_inv_N_plus_top_pendant_on_right_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 c e /\ R2 b e /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
         (x = c /\ y = e) \/ (x = b /\ y = e) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc [HRce [HRbe HRde_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRde_HR_only as [HRde HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, a=1, d=2, c=3, e=4.
     L2: d=0, b=1, c=2, e=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxc Hye] | [[Hxb Hye] | [Hxd Hye]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxc Hye] | [[Hxb Hye] | [Hxd Hye]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRce
            | exact HRbe
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 N-shape with bottom pendant on the left chain.

    Carrier [a, b, c, d, e] pairwise distinct.  N-shape with [a < b],
    [c < b], [c < d].  Element [e] sits below [a] only ([e < a]),
    which transitively gives [e < b] (via [e < a < b]).  Total 5
    R-edges: [a < b], [c < b], [c < d], [e < a], [e < b].
    Incomparable pairs: [{a, c}], [{a, d}], [{b, d}], [{c, e}], [{d, e}].

    2-realizer:
      [L1] orders [e < a < c < b < d];
      [L2] orders [c < d < e < a < b].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_N_plus_bot_pendant_on_left_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 c b /\ R2 c d /\ R2 e a /\ R2 e b /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = c /\ y = b) \/ (x = c /\ y = d) \/
         (x = e /\ y = a) \/ (x = e /\ y = b)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRcb [HRcd [HRea HReb_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HReb_HR_only as [HReb HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, a=1, c=2, b=3, d=4.
     L2: c=0, d=1, e=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxe Hya] | [Hxe Hyb]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxc Hyb] | [[Hxc Hyd] | [[Hxe Hya] | [Hxe Hyb]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRcb
            | exact HRcd
            | exact HRea
            | exact HReb
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ac : L1 a c) by (unfold L1; rewrite Hrk1_a, Hrk1_c; lia).
      assert (HL2ac : L2 a c) by (rewrite <- Heq; exact HL1ac).
      unfold L2 in HL2ac. rewrite Hrk2_a, Hrk2_c in HL2ac. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-N-shape with top pendant on the left chain.

    Carrier [a, b, c, d, e] pairwise distinct.  inv-N-shape with
    [b < a], [b < c], [d < c].  Element [e] sits above [a] only
    ([a < e]), which transitively gives [b < e] (via [b < a < e]).
    Total 5 R-edges: [b < a], [b < c], [d < c], [a < e], [b < e].
    Incomparable pairs: [{a, c}], [{a, d}], [{b, d}], [{c, e}], [{d, e}].

    Dual of [n5_N_plus_bot_pendant_on_left_two_realizer].

    2-realizer:
      [L1] orders [d < b < c < a < e];
      [L2] orders [b < a < e < d < c].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_inv_N_plus_top_pendant_on_left_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 a e /\ R2 b e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
         (x = a /\ y = e) \/ (x = b /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc [HRae HRbe_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HRbe_HR_only as [HRbe HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, b=1, c=2, a=3, e=4.
     L2: b=0, a=1, e=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxa Hye] | [Hxb Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxa Hye] | [Hxb Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRae
            | exact HRbe
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ca : L1 c a) by (unfold L1; rewrite Hrk1_c, Hrk1_a; lia).
      assert (HL2ca : L2 c a) by (rewrite <- Heq; exact HL1ca).
      unfold L2 in HL2ca. rewrite Hrk2_c, Hrk2_a in HL2ca. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-N-shape with bottom pendant on the right (d-chain) chain.

    Carrier [a, b, c, d, e] pairwise distinct.  inv-N-shape with
    [b < a], [b < c], [d < c].  Element [e] sits below [d] only
    ([e < d]), which transitively gives [e < c] (via [e < d < c]).
    Total 5 R-edges: [b < a], [b < c], [d < c], [e < d], [e < c].
    Incomparable pairs: [{a, c}], [{a, d}], [{a, e}], [{b, d}], [{b, e}].

    2-realizer:
      [L1] orders [e < d < b < c < a];
      [L2] orders [b < a < e < d < c].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_inv_N_plus_bot_pendant_on_right_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 b c /\ R2 d c /\ R2 e d /\ R2 e c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = b /\ y = c) \/ (x = d /\ y = c) \/
         (x = e /\ y = d) \/ (x = e /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRbc [HRdc [HRed HRec_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HRec_HR_only as [HRec HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, b=2, c=3, a=4.
     L2: b=0, a=1, e=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxe Hyd] | [Hxe Hyc]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxb Hyc] | [[Hxd Hyc] | [[Hxe Hyd] | [Hxe Hyc]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRbc
            | exact HRdc
            | exact HRed
            | exact HRec
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ca : L1 c a) by (unfold L1; rewrite Hrk1_c, Hrk1_a; lia).
      assert (HL2ca : L2 c a) by (rewrite <- Heq; exact HL1ca).
      unfold L2 in HL2ca. rewrite Hrk2_c, Hrk2_a in HL2ca. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 "3-fan" — common min [a], common max [d], with three
    pairwise-incomparable middle elements [b], [c], [e].

    Edges: [a < b], [a < c], [a < e], [b < d], [c < d], [e < d],
    [a < d] (7 edges).  Self-dual under swap [a <-> d].

    2-realizer: L1 orders [a < b < c < e < d]; L2 orders [a < e < c < b < d].
    Both extend the 7 edges.  L1 and L2 disagree on every pair drawn from
    [{b, c, e}], pinning the intersection to exactly the 7 listed pairs. *)
Lemma n5_3fan_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a e /\ R2 b d /\ R2 c d /\ R2 e d /\ R2 a d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = e) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/ (x = e /\ y = d) \/
         (x = a /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRae [HRbd [HRcd [HRed [HRad HR_only]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, e=3, d=4.
     L2: a=0, e=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hye] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxe Hyd] | [Hxa Hyd]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hye] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxe Hyd] | [Hxa Hyd]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRae
            | exact HRbd
            | exact HRcd
            | exact HRed
            | exact HRad
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 pentagon [N_5] — bottom [a], top [e], one side
    [a < d < e] (length-2 chain), other side [a < b < c < e] (length-3
    chain).

    Edges (8 total, plus reflexive): [a<b], [a<c], [a<d], [a<e],
    [b<c], [b<e], [c<e], [d<e].  Incomparable pairs: [(b, d)] and
    [(c, d)].

    2-realizer: L1 orders [a < d < b < c < e]; L2 orders
    [a < b < c < d < e].  Both extend the 8 edges; they reverse
    [d] vs [b] and [d] vs [c], yielding intersection = R2. *)
Lemma n5_pentagon_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 a e /\
     R2 b c /\ R2 b e /\ R2 c e /\ R2 d e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = a /\ y = e) \/ (x = b /\ y = c) \/ (x = b /\ y = e) \/
         (x = c /\ y = e) \/ (x = d /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRae [HRbc [HRbe [HRce [HRde HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, d=1, b=2, c=3, e=4.
     L2: a=0, b=1, c=2, d=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyc] | [[Hxb Hye] | [[Hxc Hye] | [Hxd Hye]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyc] | [[Hxb Hye] | [[Hxc Hye] | [Hxd Hye]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRae
            | exact HRbc
            | exact HRbe
            | exact HRce
            | exact HRde
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1db : L1 d b) by (unfold L1; rewrite Hrk1_d, Hrk1_b; lia).
      assert (HL2db : L2 d b) by (rewrite <- Heq; exact HL1db).
      unfold L2 in HL2db. rewrite Hrk2_d, Hrk2_b in HL2db. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 "kite" — apex [a] below three children [b], [c], [d];
    [b] additionally below [e]; [a] transitively below [e].

    Edges (5 total, plus reflexive): [a<b], [a<c], [a<d], [b<e], [a<e].
    Incomparable pairs: [(b,c)], [(b,d)], [(c,d)], [(c,e)], [(d,e)].

    2-realizer: L1 orders [a < c < d < b < e]; L2 orders
    [a < b < e < d < c].  Both extend the 5 edges; the five incomparable
    pairs are reversed across L1, L2, pinning the intersection to R2. *)
Lemma n5_kite_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 b e /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = e) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRbe [HRae HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, c=1, d=2, b=3, e=4.
     L2: a=0, b=1, e=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hye] | [Hxa Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRbe
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cb : L1 c b) by (unfold L1; rewrite Hrk1_c, Hrk1_b; lia).
      assert (HL2cb : L2 c b) by (rewrite <- Heq; exact HL1cb).
      unfold L2 in HL2cb. rewrite Hrk2_c, Hrk2_b in HL2cb. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 "inverse kite" — apex [a] above three parents [b], [c],
    [d]; [e] additionally below [b]; transitively [e] below [a].
    Dual (order-reverse) of [n5_kite_two_realizer].

    Edges (5 total, plus reflexive): [b<a], [c<a], [d<a], [e<b], [e<a].
    Incomparable pairs: [(b,c)], [(b,d)], [(c,d)], [(c,e)], [(d,e)].

    2-realizer: L1 orders [e < b < d < c < a]; L2 orders
    [c < d < e < b < a].  Both extend the 5 edges; the five incomparable
    pairs are reversed across L1, L2, pinning the intersection to R2. *)
Lemma n5_inv_kite_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 b a /\ R2 c a /\ R2 d a /\ R2 e b /\ R2 e a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = b /\ y = a) \/ (x = c /\ y = a) \/ (x = d /\ y = a) \/
         (x = e /\ y = b) \/ (x = e /\ y = a)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRba [HRca [HRda [HReb [HRea HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, b=1, d=2, c=3, a=4.
     L2: c=0, d=1, e=2, b=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [[Hxe Hyb] | [Hxe Hya]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxb Hya] | [[Hxc Hya] | [[Hxd Hya] | [[Hxe Hyb] | [Hxe Hya]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRba
            | exact HRca
            | exact HRda
            | exact HReb
            | exact HRea
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1dc : L1 d c) by (unfold L1; rewrite Hrk1_d, Hrk1_c; lia).
      assert (HL2dc : L2 d c) by (rewrite <- Heq; exact HL1dc).
      unfold L2 in HL2dc. rewrite Hrk2_d, Hrk2_c in HL2dc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 "3-layer diamond" — bottom [a], middle pair [b], [c],
    top pair [d], [e], with [b], [c] both below both [d], [e].  This is
    the bipartite K_{2,2} on [{b, c}, {d, e}] capped with a single common
    minimum [a].

    Edges (8 total, plus reflexive): [a<b], [a<c], [b<d], [c<d], [b<e],
    [c<e] together with the transitive consequences [a<d] and [a<e].
    Incomparable pairs: [(b, c)] and [(d, e)].

    2-realizer: L1 orders [a < b < c < d < e]; L2 orders
    [a < c < b < e < d].  Both extend the 8 edges; the two incomparable
    pairs are reversed across L1, L2, pinning the intersection to R2. *)
Lemma n5_3_layer_diamond_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 b e /\ R2 c e /\
     R2 a d /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/
         (x = b /\ y = e) \/ (x = c /\ y = e) \/
         (x = a /\ y = d) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRbe [HRce [HRad [HRae HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, c=1, b=2, e=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxb Hye] | [[Hxc Hye] | [[Hxa Hyd] | [Hxa Hye]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxb Hye] | [[Hxc Hye] | [[Hxa Hyd] | [Hxa Hye]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRbe
            | exact HRce
            | exact HRad
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 "bowtie + top cap" — K_{2,2,1} 3-layer poset with two
    bottom elements [a], [b], two middle elements [c], [d], and a single
    top [e].  Both bottoms are below both middles (bowtie), and both
    middles are below the top.

    Edges (8 total, plus reflexive): [a<c], [a<d], [b<c], [b<d], [c<e],
    [d<e] together with the transitive consequences [a<e], [b<e].
    Incomparable pairs: [(a, b)] and [(c, d)].

    2-realizer: L1 orders [a < b < c < d < e]; L2 orders
    [b < a < d < c < e].  Both extend the 8 edges; the two incomparable
    pairs are reversed across L1, L2, pinning the intersection to R2. *)
Lemma n5_bowtie_top_cap_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 a d /\ R2 b c /\ R2 b d /\ R2 c e /\ R2 d e /\
     R2 a e /\ R2 b e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = c) \/ (x = b /\ y = d) \/
         (x = c /\ y = e) \/ (x = d /\ y = e) \/
         (x = a /\ y = e) \/ (x = b /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRad [HRbc [HRbd [HRce [HRde [HRae [HRbe HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: b=0, a=1, d=2, c=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    reflexivity. }
  assert (Hrk2_b : rk2 b = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = b)) as [He|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = b)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = b)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [[Hxb Hyd] | [[Hxc Hye] | [[Hxd Hye] | [[Hxa Hye] | [Hxb Hye]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [[Hxb Hyd] | [[Hxc Hye] | [[Hxd Hye] | [[Hxa Hye] | [Hxb Hye]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRad
            | exact HRbc
            | exact HRbd
            | exact HRce
            | exact HRde
            | exact HRae
            | exact HRbe
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 "bowtie + bottom cap" — K_{1,2,2} 3-layer poset, dual
    of [n5_bowtie_top_cap_two_realizer].  Common bottom [e], two middle
    [c], [d], two top [a], [b].  Every bottom is below every middle, and
    every middle is below every top.

    Edges (8 total, plus reflexive): [e<c], [e<d], [c<a], [c<b], [d<a],
    [d<b] together with the transitive consequences [e<a], [e<b].
    Incomparable pairs: [(a, b)] and [(c, d)].

    2-realizer: L1 orders [e < d < c < b < a]; L2 orders
    [e < c < d < a < b].  Both extend the 8 edges; the two incomparable
    pairs are reversed across L1, L2, pinning the intersection to R2. *)
Lemma n5_bowtie_bot_cap_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 e c /\ R2 e d /\ R2 c a /\ R2 c b /\ R2 d a /\ R2 d b /\
     R2 e a /\ R2 e b /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = e /\ y = c) \/ (x = e /\ y = d) \/
         (x = c /\ y = a) \/ (x = c /\ y = b) \/
         (x = d /\ y = a) \/ (x = d /\ y = b) \/
         (x = e /\ y = a) \/ (x = e /\ y = b)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRec [HRed [HRca [HRcb [HRda [HRdb [HRea [HReb HR_only]]]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, c=2, b=3, a=4.
     L2: e=0, c=1, d=2, a=3, b=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxe Hyc] | [[Hxe Hyd] | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] | [[Hxd Hyb] | [[Hxe Hya] | [Hxe Hyb]]]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxe Hyc] | [[Hxe Hyd] | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] | [[Hxd Hyb] | [[Hxe Hya] | [Hxe Hyb]]]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRec
            | exact HRed
            | exact HRca
            | exact HRcb
            | exact HRda
            | exact HRdb
            | exact HRea
            | exact HReb
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1dc : L1 d c) by (unfold L1; rewrite Hrk1_d, Hrk1_c; lia).
      assert (HL2dc : L2 d c) by (rewrite <- Heq; exact HL1dc).
      unfold L2 in HL2dc. rewrite Hrk2_d, Hrk2_c in HL2dc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 V-shape with chain extending one leaf, plus isolated.

    Carrier [a, b, c, d, e] pairwise distinct.  V-shape with apex [a]
    and leaves [b], [c] ([a < b], [a < c]).  Chain extends leaf [b]
    upward via [b < d], with transitive [a < d].  Element [e] is
    isolated.  Total 4 R-edges: [a < b], [a < c], [b < d], [a < d].
    Incomparable pairs: [{b, c}], [{c, d}], [{a, e}], [{b, e}],
    [{c, e}], [{d, e}].

    2-realizer:
      [L1] orders [a < b < d < c < e];
      [L2] orders [e < a < c < b < d].
    Both extend the 4 edges; every incomparable pair is reversed
    between the two extensions, pinning the intersection to R2. *)
Lemma n5_V_chain_one_leaf_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 a d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = b /\ y = d) \/
         (x = a /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd HRad_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRad_HR_only as [HRad HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, d=2, c=3, e=4.
     L2: e=0, a=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [Hxa Hyd]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [Hxa Hyd]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRad
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 inv-V-shape with chain extending one bottom, plus isolated.

    Carrier [a, b, c, d, e] pairwise distinct.  Inv-V with apex [c]
    and bottoms [a], [b] ([a < c], [b < c]).  Chain extends bottom
    [a] downward via [d < a], with transitive [d < c].  Element [e]
    is isolated.  Total 4 R-edges: [a < c], [b < c], [d < a], [d < c].
    Incomparable pairs: [{a, b}], [{b, d}], [{a, e}], [{b, e}],
    [{c, e}], [{d, e}].  Dual of [n5_V_chain_one_leaf_plus_isolated].

    2-realizer:
      [L1] orders [e < b < d < a < c];
      [L2] orders [d < a < b < c < e].
    Both extend the 4 edges; every incomparable pair is reversed
    between the two extensions, pinning the intersection to R2. *)
Lemma n5_inv_V_chain_one_leaf_plus_isolated_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 b c /\ R2 d a /\ R2 d c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = b /\ y = c) \/ (x = d /\ y = a) \/
         (x = d /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRbc [HRda HRdc_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRdc_HR_only as [HRdc HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, b=1, d=2, a=3, c=4.
     L2: d=0, a=1, b=2, c=3, e=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxd Hya] | [Hxd Hyc]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxd Hya] | [Hxd Hyc]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRbc
            | exact HRda
            | exact HRdc
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bd : L1 b d) by (unfold L1; rewrite Hrk1_b, Hrk1_d; lia).
      assert (HL2bd : L2 b d) by (rewrite <- Heq; exact HL1bd).
      unfold L2 in HL2bd. rewrite Hrk2_b, Hrk2_d in HL2bd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 diamond + a pendant below the top only (no transitives).

    Carrier [a, b, c, d, e] pairwise distinct.  Diamond on
    [{a, b, c, d}]: [a < b], [a < c], [b < d], [c < d] with transitive
    [a < d].  Pendant [e < d] sits below the diamond top [d] only; [e]
    is incomparable to [a], [b], [c].  Total 6 R-edges: [a < b],
    [a < c], [b < d], [c < d], [a < d], [e < d].  Incomparable pairs:
    [{b, c}], [{a, e}], [{b, e}], [{c, e}].

    Distinct from [n5_diamond_pendant_below_two_realizer] which places
    the pendant below the diamond bottom [a] (and forces transitive
    [e<b], [e<c], [e<d] — 9 edges).

    2-realizer:
      [L1] orders [a < b < c < e < d];
      [L2] orders [e < a < c < b < d].
    Both extend the 6 edges; [b<c] and [c<b] are reversed across L1/L2,
    and pendant [e] is on opposite ends in the two extensions, pinning
    the intersection to R2. *)
Lemma n5_diamond_pendant_top_only_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 a d /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/
         (x = a /\ y = d) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRad HRed_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRed_HR_only as [HRed HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, e=3, d=4.
     L2: e=0, a=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] | [Hxe Hyd]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] | [Hxe Hyd]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRad
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 diamond + a pendant above the bottom only (no transitives).

    Carrier [a, b, c, d, e] pairwise distinct.  Diamond on
    [{a, b, c, d}]: [a < b], [a < c], [b < d], [c < d] with transitive
    [a < d].  Pendant [a < e] sits above the diamond bottom [a] only;
    [e] is incomparable to [b], [c], [d].  Total 6 R-edges: [a < b],
    [a < c], [b < d], [c < d], [a < d], [a < e].  Incomparable pairs:
    [{b, c}], [{b, e}], [{c, e}], [{d, e}].

    Dual of [n5_diamond_pendant_top_only_two_realizer].  Distinct from
    [n5_diamond_pendant_above_two_realizer] which places [d < e] above
    the diamond top [d] (and forces transitive [a<e], [b<e], [c<e] —
    9 edges).

    2-realizer:
      [L1] orders [a < b < c < d < e];
      [L2] orders [a < e < c < b < d].
    Both extend the 6 edges; [b<c] and [c<b] are reversed across L1/L2,
    and pendant [e] is on opposite ends of {b, c, d} in the two
    extensions, pinning the intersection to R2. *)
Lemma n5_diamond_pendant_bot_only_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b d /\ R2 c d /\ R2 a d /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/
         (x = b /\ y = d) \/ (x = c /\ y = d) \/
         (x = a /\ y = d) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbd [HRcd [HRad HRae_HR_only]]]]]]]]]]]]]]]]]]]].
  destruct HRae_HR_only as [HRae HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, e=1, c=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] | [Hxa Hye]]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyd] | [[Hxc Hyd] | [[Hxa Hyd] | [Hxa Hye]]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbd
            | exact HRcd
            | exact HRad
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1bc : L1 b c) by (unfold L1; rewrite Hrk1_b, Hrk1_c; lia).
      assert (HL2bc : L2 b c) by (rewrite <- Heq; exact HL1bc).
      unfold L2 in HL2bc. rewrite Hrk2_b, Hrk2_c in HL2bc. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 K_{2,3} minus one edge.

    Carrier [a, b, c, d, e] pairwise distinct.  Elements [a, b] form the
    top antichain and [c, d, e] form the bottom antichain.  Bottoms [c]
    and [d] are below both tops; bottom [e] is below only [a] (i.e. the
    edge [e < b] of K_{2,3} is removed).  Total 5 R-edges: [c < a],
    [c < b], [d < a], [d < b], [e < a].  Incomparable pairs: [{a, b}],
    [{c, d}], [{c, e}], [{d, e}], [{b, e}].

    Equivalently: a K_{2,2} bowtie on [{a, b, c, d}] (tops [a, b],
    bottoms [c, d]) plus an extra "half-bottom" pendant [e < a].

    2-realizer:
      [L1] orders [e < c < d < a < b];
      [L2] orders [d < c < b < e < a].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_K_2_3_minus_edge_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c a /\ R2 c b /\ R2 d a /\ R2 d b /\ R2 e a /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = a) \/ (x = c /\ y = b) \/
         (x = d /\ y = a) \/ (x = d /\ y = b) \/
         (x = e /\ y = a)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRca [HRcb [HRda [HRdb HRea_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HRea_HR_only as [HRea HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, c=1, d=2, a=3, b=4.
     L2: d=0, c=1, b=2, e=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_d : rk2 d = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] | [[Hxd Hyb] | [Hxe Hya]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_a. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] | [[Hxd Hyb] | [Hxe Hya]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_a. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRca
            | exact HRcb
            | exact HRda
            | exact HRdb
            | exact HRea
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 K_{3,2} minus one edge.

    Carrier [a, b, c, d, e] pairwise distinct.  Elements [a, b] form the
    bottom antichain and [c, d, e] form the top antichain.  Bottoms
    [a, b] are both below [c, d]; bottom [a] is also below [e], but
    bottom [b] is NOT below [e] (i.e. the edge [b < e] of K_{3,2} is
    removed).  Total 5 R-edges: [a < c], [a < d], [a < e], [b < c],
    [b < d].  Incomparable pairs: [{a, b}], [{c, d}], [{c, e}],
    [{d, e}], [{b, e}].

    Dual of [n5_K_2_3_minus_edge_two_realizer].  Equivalently a bowtie
    K_{2,2} on [{a, b, c, d}] (bottoms [a, b], tops [c, d]) plus an
    extra "half-top" pendant [a < e].

    2-realizer:
      [L1] orders [b < a < c < d < e];
      [L2] orders [a < e < b < d < c].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_K_3_2_minus_edge_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a c /\ R2 a d /\ R2 a e /\ R2 b c /\ R2 b d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = c) \/ (x = a /\ y = d) \/ (x = a /\ y = e) \/
         (x = b /\ y = c) \/ (x = b /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRac [HRad [HRae [HRbc HRbd_HR_only]]]]]]]]]]]]]]]]]]].
  destruct HRbd_HR_only as [HRbd HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, a=1, c=2, d=3, e=4.
     L2: a=0, e=1, b=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyc] | [Hxb Hyd]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyc] | [Hxb Hyd]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRac
            | exact HRad
            | exact HRae
            | exact HRbc
            | exact HRbd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1cd : L1 c d) by (unfold L1; rewrite Hrk1_c, Hrk1_d; lia).
      assert (HL2cd : L2 c d) by (rewrite <- Heq; exact HL1cd).
      unfold L2 in HL2cd. rewrite Hrk2_c, Hrk2_d in HL2cd. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 K_{2,3} minus two edges (from different bottoms,
    going to different tops).

    Carrier [a, b, c, d, e] pairwise distinct.  Elements [a, b] form
    the top antichain and [c, d, e] form the bottom antichain.  Bottom
    [c] is below both tops [a] and [b]; bottom [d] is below only [a];
    bottom [e] is below only [b].  Equivalently, K_{2,3} with the two
    edges [d < b] and [e < a] removed.  Total 4 R-edges: [c < a],
    [c < b], [d < a], [e < b].  Incomparable pairs: [{a, b}], [{c, d}],
    [{c, e}], [{d, e}], [{b, d}], [{a, e}].

    Distinct from [n5_K_2_3_minus_edge_two_realizer] (5 edges, one
    "half-pendant").  Distinct from [n5_bowtie_plus_isolated_two_realizer]
    where the third bottom is fully isolated.  Distinct from
    [n5_N_plus_isolated_two_realizer] (only 3 edges in N-shape).

    2-realizer:
      [L1] orders [d < c < a < e < b];
      [L2] orders [e < c < b < d < a].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_K_2_3_minus_two_edges_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 c a /\ R2 c b /\ R2 d a /\ R2 e b /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = c /\ y = a) \/ (x = c /\ y = b) \/
         (x = d /\ y = a) \/ (x = e /\ y = b)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRca [HRcb [HRda HReb_HR_only]]]]]]]]]]]]]]]]]].
  destruct HReb_HR_only as [HReb HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, c=1, a=2, e=3, b=4.
     L2: e=0, c=1, b=2, d=3, a=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] | [Hxe Hyb]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_a. lia.
    - subst x y. unfold L1. rewrite Hrk1_e, Hrk1_b. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxc Hya] | [[Hxc Hyb] | [[Hxd Hya] | [Hxe Hyb]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_a. lia.
    - subst x y. unfold L2. rewrite Hrk2_e, Hrk2_b. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRca
            | exact HRcb
            | exact HRda
            | exact HReb
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 K_{3,2} minus two edges (from different tops, going to
    different bottoms going up — i.e. dual of [n5_K_2_3_minus_two_edges]).

    Carrier [a, b, c, d, e] pairwise distinct.  Elements [a, b, c] form
    the bottom antichain and [d, e] form the top antichain.  Bottom [a]
    is below only [d]; bottom [b] is below only [d]; bottom [c] is below
    both tops [d] and [e].  Equivalently, K_{3,2} with the two edges
    [a < e] and [b < e] removed.  Total 4 R-edges: [a < d], [b < d],
    [c < d], [c < e].  Incomparable pairs: [{d, e}], [{a, b}], [{a, c}],
    [{b, c}], [{a, e}], [{b, e}].

    Dual of [n5_K_2_3_minus_two_edges_two_realizer].  Distinct from
    [n5_K_3_2_minus_edge_two_realizer] (5 edges, one "half-pendant").

    2-realizer:
      [L1] orders [a < b < c < d < e];
      [L2] orders [c < e < b < a < d].
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_K_3_2_minus_two_edges_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a d /\ R2 b d /\ R2 c d /\ R2 c e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = d) \/ (x = b /\ y = d) \/
         (x = c /\ y = d) \/ (x = c /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRad [HRbd [HRcd HRce_HR_only]]]]]]]]]]]]]]]]]].
  destruct HRce_HR_only as [HRce HR_only].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: c=0, e=1, b=2, a=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = c) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_c : rk2 c = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq |].
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq |].
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyd] | [[Hxb Hyd] | [[Hxc Hyd] | [Hxc Hye]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_d. lia.
    - subst x y. unfold L1. rewrite Hrk1_c, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyd] | [[Hxb Hyd] | [[Hxc Hyd] | [Hxc Hye]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_d. lia.
    - subst x y. unfold L2. rewrite Hrk2_c, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRad
            | exact HRbd
            | exact HRcd
            | exact HRce
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ab : L1 a b) by (unfold L1; rewrite Hrk1_a, Hrk1_b; lia).
      assert (HL2ab : L2 a b) by (rewrite <- Heq; exact HL1ab).
      unfold L2 in HL2ab. rewrite Hrk2_a, Hrk2_b in HL2ab. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 3-chain with a top pendant and a bottom pendant.

    Carrier [a, b, c, d, e] pairwise distinct.  Strict edges form
    the 3-chain [a < b < c] with [a < c] by transitivity; a pendant
    [d < c] below the top of the chain; and a pendant [a < e] above
    the bottom of the chain.  Five direct strict pairs (no
    additional transitives).

    Explicit 2-realizer (rank-encoded):
    - L1: d < a < b < c < e.
    - L2: a < e < b < d < c.

    Direct verification: every R2-edge respects both L1 and L2;
    each of the five incomparable pairs (a, d), (b, d), (b, e),
    (c, e), (d, e) is flipped between the two linearisations. *)
Lemma n5_chain3_bot_pendant_and_top_pendant_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 b c /\ R2 a c /\ R2 d c /\ R2 a e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = b /\ y = c) \/ (x = a /\ y = c) \/
         (x = d /\ y = c) \/ (x = a /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRbc [HRac [HRdc [HRae HR_only]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: d=0, a=1, b=2, c=3, e=4.
     L2: a=0, e=1, b=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = d) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_d : rk1 d = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  assert (Hrk1_inj : forall x y, rk1 x = rk1 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in Hxy;
              discriminate ]. }
  assert (Hrk2_inj : forall x y, rk2 x = rk2 y -> x = y).
  { intros x y Hxy.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ reflexivity
            | exfalso;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in Hxy;
              discriminate ]. }
  set (L1 := fun x y : B => rk1 x <= rk1 y).
  set (L2 := fun x y : B => rk2 x <= rk2 y).
  assert (HL1_pos : IsPoset B L1).
  { constructor; unfold L1.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk1_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL1_total : forall x y, L1 x y \/ L1 y x).
  { intros x y. unfold L1. lia. }
  assert (HL1_tot : IsTotalOrder L1).
  { constructor; [exact HL1_pos | exact HL1_total]. }
  assert (HL1_ext : forall x y, R2 x y -> L1 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyc] | [Hxa Hye]]]]]].
    - subst y. unfold L1. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_b. lia.
    - subst x y. unfold L1. rewrite Hrk1_b, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_d, Hrk1_c. lia.
    - subst x y. unfold L1. rewrite Hrk1_a, Hrk1_e. lia. }
  assert (HL1_lin : IsLinearExtension R2 L1).
  { constructor; [exact HL1_tot | exact HL1_ext]. }
  assert (HL2_pos : IsPoset B L2).
  { constructor; unfold L2.
    - intro x. lia.
    - intros x y Hxy Hyx. apply Hrk2_inj. lia.
    - intros x y z Hxy Hyz. lia. }
  assert (HL2_total : forall x y, L2 x y \/ L2 y x).
  { intros x y. unfold L2. lia. }
  assert (HL2_tot : IsTotalOrder L2).
  { constructor; [exact HL2_pos | exact HL2_total]. }
  assert (HL2_ext : forall x y, R2 x y -> L2 x y).
  { intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxb Hyc] | [[Hxa Hyc] | [[Hxd Hyc] | [Hxa Hye]]]]]].
    - subst y. unfold L2. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_b. lia.
    - subst x y. unfold L2. rewrite Hrk2_b, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_d, Hrk2_c. lia.
    - subst x y. unfold L2. rewrite Hrk2_a, Hrk2_e. lia. }
  assert (HL2_lin : IsLinearExtension R2 L2).
  { constructor; [exact HL2_tot | exact HL2_ext]. }
  assert (Hinter : forall x y, L1 x y -> L2 x y -> R2 x y).
  { intros x y HLa HLb.
    unfold L1 in HLa; unfold L2 in HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRbc
            | exact HRac
            | exact HRdc
            | exact HRae
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ]. }
  set (rls := Add (B -> B -> Prop) (Singleton _ L1) L2).
  exists rls. split.
  - constructor.
    + intros L HL. destruct HL as [L HL | L HL].
      * destruct HL. exact HL1_lin.
      * destruct HL. exact HL2_lin.
    + intros x y. split.
      * intros HRxy L HL. destruct HL as [L HL | L HL].
        { destruct HL. exact (HL1_lin.(linear_extends) x y HRxy). }
        { destruct HL. exact (HL2_lin.(linear_extends) x y HRxy). }
      * intro Hall.
        assert (HLa : L1 x y)
          by exact (Hall L1 (Union_introl _ _ _ _ (In_singleton _ _))).
        assert (HLb : L2 x y)
          by exact (Hall L2 (Union_intror _ _ _ _ (In_singleton _ _))).
        exact (Hinter x y HLa HLb).
  - assert (HL_neq : L1 <> L2).
    { intro Heq.
      assert (HL1ad : L1 d a) by (unfold L1; rewrite Hrk1_d, Hrk1_a; lia).
      assert (HL2ad : L2 d a) by (rewrite <- Heq; exact HL1ad).
      unfold L2 in HL2ad. rewrite Hrk2_d, Hrk2_a in HL2ad. lia. }
    unfold rls.
    apply card_add.
    + exact (singleton_cardinal _ L1).
    + intro Hin. destruct Hin. apply HL_neq. reflexivity.
Qed.

(** Sub-case: n=5 K_{3,2} minus a perfect matching.

    Carrier [a, b, c, d, e] pairwise distinct.  Bipartite with bottoms
    [a, b, c] and tops [d, e]; the 6 K_{3,2} edges minus the matching
    [{a < d, b < e}] leave exactly 4 R-edges:
    [a < e], [b < d], [c < d], [c < e].
    Incomparable pairs: [{a, b}], [{a, c}], [{a, d}], [{b, c}],
    [{b, e}], [{d, e}].

    Distinct from [n5_K_3_2_minus_two_edges_two_realizer] (which removes
    two edges incident to the SAME top, yielding tops of degrees 3 and 1)
    and from [n5_bowtie_plus_isolated_two_realizer] (which would arise
    from removing two edges incident to the same bottom).

    KNOWN ISOMORPHIC TO [n5_K_2_3_minus_two_edges_two_realizer]: relabel
    bottoms (a, b, c) → (d, e, c) and tops (d, e) → (a, b); both classes
    have a central element connecting to both elements of the opposite
    side plus two "pendant" connections.  This lemma is preserved as a
    Qed-closed alternate-shape proof but the dispatcher branch below
    is unreachable in practice — the earlier K_{2,3}_minus_two_edges
    branch fires first via classical existential pattern matching.

    2-realizer (rank-encoded):
    - L1: b < c < d < a < e.
    - L2: a < c < e < b < d.
    Every incomparable pair is flipped between [L1] and [L2]. *)
Lemma n5_K_3_2_minus_matching_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a e /\ R2 b d /\ R2 c d /\ R2 c e /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = e) \/ (x = b /\ y = d) \/
         (x = c /\ y = d) \/ (x = c /\ y = e)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRae [HRbd [HRcd [HRce HR_only]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: b=0, c=1, d=2, a=3, e=4.
     L2: a=0, c=1, e=2, b=3, d=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = b) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = a) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = c) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_b : rk1 b = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = b)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (a = c)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = c)) as [He'|_]; [contradiction Hbc_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; auto |].
    reflexivity. }
  apply (@n5_two_realizer_framework B R2 HR2 a b c d e
           Hab_neq Hac_neq Had_neq Hae_neq Hbc_neq Hbd_neq Hbe_neq
           Hcd_neq Hce_neq Hde_neq Hcovers rk1 rk2);
    try (rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e; lia);
    try (rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e; lia).
  - (* rk1 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hye] | [[Hxb Hyd] | [[Hxc Hyd] | [Hxc Hye]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_e. lia.
    + subst x y. rewrite Hrk1_b, Hrk1_d. lia.
    + subst x y. rewrite Hrk1_c, Hrk1_d. lia.
    + subst x y. rewrite Hrk1_c, Hrk1_e. lia.
  - (* rk2 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hye] | [[Hxb Hyd] | [[Hxc Hyd] | [Hxc Hye]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_e. lia.
    + subst x y. rewrite Hrk2_b, Hrk2_d. lia.
    + subst x y. rewrite Hrk2_c, Hrk2_d. lia.
    + subst x y. rewrite Hrk2_c, Hrk2_e. lia.
  - (* L1 ∩ L2 ⊆ R2 — 25-cell enumeration *)
    intros x y HLa HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRae
            | exact HRbd
            | exact HRcd
            | exact HRce
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ].
  - (* Distinguishing pair: (b, c) gives L1 b<c but L2 c<b. *)
    exists b, c. rewrite Hrk1_b, Hrk1_c, Hrk2_b, Hrk2_c. lia.
Qed.

(** Class 31: 6 strict edges [a<b], [a<c], [a<d], [a<e], [b<c], [b<d];
    incomparable pairs {c,d}, {c,e}, {d,e}, {b,e}.

    [a] is bottom; [b] sits above [a] and below [c], [d]; [c], [d], [e]
    form an antichain at the top with [e] only connected upward to [a].

    Realizer: L1 = a<b<c<d<e; L2 = a<e<b<d<c. *)
Lemma n5_class31_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 a e /\ R2 b c /\ R2 b d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = a /\ y = e) \/ (x = b /\ y = c) \/ (x = b /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRae [HRbc [HRbd HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, c=2, d=3, e=4.
     L2: a=0, e=1, b=2, d=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = c) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = e) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = d) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = c)) as [He'|_]; [contradiction Hce_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; auto |].
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    reflexivity. }
  apply (@n5_two_realizer_framework B R2 HR2 a b c d e
           Hab_neq Hac_neq Had_neq Hae_neq Hbc_neq Hbd_neq Hbe_neq
           Hcd_neq Hce_neq Hde_neq Hcovers rk1 rk2);
    try (rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e; lia);
    try (rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e; lia).
  - (* rk1 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyc] | [Hxb Hyd]]]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_b. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_d. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_e. lia.
    + subst x y. rewrite Hrk1_b, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_b, Hrk1_d. lia.
  - (* rk2 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxa Hye] | [[Hxb Hyc] | [Hxb Hyd]]]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_b. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_d. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_e. lia.
    + subst x y. rewrite Hrk2_b, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_b, Hrk2_d. lia.
  - (* L1 ∩ L2 ⊆ R2 — 25-cell enumeration *)
    intros x y HLa HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRae
            | exact HRbc
            | exact HRbd
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ].
  - (* Distinguishing pair: (c, d) gives L1 c<d but L2 d<c. *)
    exists c, d. rewrite Hrk1_c, Hrk1_d, Hrk2_c, Hrk2_d. lia.
Qed.

(** Class 38: 6 strict edges [a<b], [a<c], [a<d], [b<c], [e<c], [e<d];
    incomparable pairs {a,e}, {b,d}, {b,e}, {c,d}.

    [a] below [b, c, d]; [b] below [c]; [e] below [c, d]; [a] and [e]
    incomparable; [b] and [d] incomparable.

    Realizer: L1 = a<b<e<c<d; L2 = e<a<d<b<c. *)
Lemma n5_class38_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 a d /\ R2 b c /\ R2 e c /\ R2 e d /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = a /\ y = d) \/
         (x = b /\ y = c) \/ (x = e /\ y = c) \/ (x = e /\ y = d)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRad [HRbc [HRec [HRed HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: a=0, b=1, e=2, c=3, d=4.
     L2: e=0, a=1, d=2, b=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = b) then 1%nat
                else if excluded_middle_informative (x = e) then 2%nat
                else if excluded_middle_informative (x = c) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = a) then 1%nat
                else if excluded_middle_informative (x = d) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  assert (Hrk1_a : rk1 a = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_e : rk1 e = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = c)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = b)) as [He'|_]; [contradiction Hbd_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = c)) as [He'|_]; [contradiction Hcd_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_e : rk2 e = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_a : rk2 a = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  apply (@n5_two_realizer_framework B R2 HR2 a b c d e
           Hab_neq Hac_neq Had_neq Hae_neq Hbc_neq Hbd_neq Hbe_neq
           Hcd_neq Hce_neq Hde_neq Hcovers rk1 rk2);
    try (rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e; lia);
    try (rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e; lia).
  - (* rk1 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [[Hxe Hyc] | [Hxe Hyd]]]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_b. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_d. lia.
    + subst x y. rewrite Hrk1_b, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_e, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_e, Hrk1_d. lia.
  - (* rk2 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxa Hyd] | [[Hxb Hyc] | [[Hxe Hyc] | [Hxe Hyd]]]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_b. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_d. lia.
    + subst x y. rewrite Hrk2_b, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_e, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_e, Hrk2_d. lia.
  - (* L1 ∩ L2 ⊆ R2 — 25-cell enumeration *)
    intros x y HLa HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRad
            | exact HRbc
            | exact HRec
            | exact HRed
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ].
  - (* Distinguishing pair: (b, e) gives L1 b<e but L2 e<b. *)
    exists b, e. rewrite Hrk1_b, Hrk1_e, Hrk2_b, Hrk2_e. lia.
Qed.

(** Class 40: 6 strict edges [a<b], [a<c], [b<c], [d<b], [d<c], [e<c];
    incomparable pairs {a,d}, {a,e}, {b,e}, {d,e}.

    [c] is top above all; [b] above [a, d]; [d] and [e] each below [c]
    but no other connection between them; [a] and [d] incomparable;
    [a] and [e] incomparable.

    Realizer: L1 = e<d<a<b<c; L2 = a<d<b<e<c. *)
Lemma n5_class40_two_realizer :
  forall {B : Type} (R2 : B -> B -> Prop) `{HR2 : IsPoset B R2},
  cardinal B (Full_set B) 5 ->
  (exists a b c d e : B,
     a <> b /\ a <> c /\ a <> d /\ a <> e /\
     b <> c /\ b <> d /\ b <> e /\
     c <> d /\ c <> e /\
     d <> e /\
     R2 a b /\ R2 a c /\ R2 b c /\ R2 d b /\ R2 d c /\ R2 e c /\
     (forall x y : B,
        R2 x y -> x = y \/
        ((x = a /\ y = b) \/ (x = a /\ y = c) \/ (x = b /\ y = c) \/
         (x = d /\ y = b) \/ (x = d /\ y = c) \/ (x = e /\ y = c)))) ->
  exists r : Ensemble (B -> B -> Prop),
    IsRealizer R2 r /\ cardinal (B -> B -> Prop) r 2.
Proof.
  intros B R2 HR2 Hcard
    [a [b [c [d [e [Hab_neq [Hac_neq [Had_neq [Hae_neq
       [Hbc_neq [Hbd_neq [Hbe_neq
       [Hcd_neq [Hce_neq
       [Hde_neq
       [HRab [HRac [HRbc [HRdb [HRdc [HRec HR_only]]]]]]]]]]]]]]]]]]]]].
  destruct (@carrier_5_destructure B a b Hcard Hab_neq)
    as [r [s [t [Har_neq [Has_neq [Hat_neq
                   [Hbr_neq [Hbs_neq [Hbt_neq
                   [Hrs_neq [Hrt_neq [Hst_neq Hcov5]]]]]]]]]]]].
  assert (Hcovers : forall x : B, x = a \/ x = b \/ x = c \/ x = d \/ x = e).
  { assert (Hc_in : c = r \/ c = s \/ c = t).
    { destruct (Hcov5 c) as [Hc | [Hc | [Hc | [Hc | Hc]]]].
      - contradiction Hac_neq; symmetry; exact Hc.
      - contradiction Hbc_neq; symmetry; exact Hc.
      - left; exact Hc.
      - right; left; exact Hc.
      - right; right; exact Hc. }
    assert (Hd_in : d = r \/ d = s \/ d = t).
    { destruct (Hcov5 d) as [Hd | [Hd | [Hd | [Hd | Hd]]]].
      - contradiction Had_neq; symmetry; exact Hd.
      - contradiction Hbd_neq; symmetry; exact Hd.
      - left; exact Hd.
      - right; left; exact Hd.
      - right; right; exact Hd. }
    assert (He_in : e = r \/ e = s \/ e = t).
    { destruct (Hcov5 e) as [He | [He | [He | [He | He]]]].
      - contradiction Hae_neq; symmetry; exact He.
      - contradiction Hbe_neq; symmetry; exact He.
      - left; exact He.
      - right; left; exact He.
      - right; right; exact He. }
    assert (Hr_in : r = c \/ r = d \/ r = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Hs_in : s = c \/ s = d \/ s = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    assert (Ht_in : t = c \/ t = d \/ t = e).
    { destruct Hc_in as [Hc | [Hc | Hc]];
      destruct Hd_in as [Hd | [Hd | Hd]];
      destruct He_in as [He | [He | He]];
      try (left; symmetry; exact Hc);
      try (right; left; symmetry; exact Hd);
      try (right; right; symmetry; exact He);
      try (exfalso; apply Hcd_neq; rewrite Hc, Hd; reflexivity);
      try (exfalso; apply Hce_neq; rewrite Hc, He; reflexivity);
      try (exfalso; apply Hde_neq; rewrite Hd, He; reflexivity). }
    intro x.
    destruct (Hcov5 x) as [Hx | [Hx | [Hx | [Hx | Hx]]]].
    - auto.
    - auto.
    - subst x. destruct Hr_in as [Hr | [Hr | Hr]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hr.
    - subst x. destruct Hs_in as [Hs | [Hs | Hs]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Hs.
    - subst x. destruct Ht_in as [Ht | [Ht | Ht]];
        [right; right; left | right; right; right; left | right; right; right; right];
        exact Ht. }
  (* L1: e=0, d=1, a=2, b=3, c=4.
     L2: a=0, d=1, b=2, e=3, c=4. *)
  set (rk1 := fun x : B =>
                if excluded_middle_informative (x = e) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = a) then 2%nat
                else if excluded_middle_informative (x = b) then 3%nat
                else 4%nat).
  set (rk2 := fun x : B =>
                if excluded_middle_informative (x = a) then 0%nat
                else if excluded_middle_informative (x = d) then 1%nat
                else if excluded_middle_informative (x = b) then 2%nat
                else if excluded_middle_informative (x = e) then 3%nat
                else 4%nat).
  assert (Hrk1_e : rk1 e = 0%nat).
  { unfold rk1. destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk1_d : rk1 d = 1%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (d = e)) as [He'|_]; [contradiction Hde_neq; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk1_a : rk1 a = 2%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (a = e)) as [He'|_]; [contradiction Hae_neq; auto |].
    destruct (excluded_middle_informative (a = d)) as [He'|_]; [contradiction Had_neq; auto |].
    destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk1_b : rk1 b = 3%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (b = e)) as [He'|_]; [contradiction Hbe_neq; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk1_c : rk1 c = 4%nat).
  { unfold rk1.
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    reflexivity. }
  assert (Hrk2_a : rk2 a = 0%nat).
  { unfold rk2. destruct (excluded_middle_informative (a = a)); [reflexivity | contradiction]. }
  assert (Hrk2_d : rk2 d = 1%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (d = a)) as [He'|_]; [contradiction Had_neq; symmetry; auto |].
    destruct (excluded_middle_informative (d = d)); [reflexivity | contradiction]. }
  assert (Hrk2_b : rk2 b = 2%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (b = a)) as [He'|_]; [contradiction Hab_neq; symmetry; auto |].
    destruct (excluded_middle_informative (b = d)) as [He'|_]; [contradiction Hbd_neq; auto |].
    destruct (excluded_middle_informative (b = b)); [reflexivity | contradiction]. }
  assert (Hrk2_e : rk2 e = 3%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (e = a)) as [He'|_]; [contradiction Hae_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = d)) as [He'|_]; [contradiction Hde_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = b)) as [He'|_]; [contradiction Hbe_neq; symmetry; auto |].
    destruct (excluded_middle_informative (e = e)); [reflexivity | contradiction]. }
  assert (Hrk2_c : rk2 c = 4%nat).
  { unfold rk2.
    destruct (excluded_middle_informative (c = a)) as [He'|_]; [contradiction Hac_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = d)) as [He'|_]; [contradiction Hcd_neq; auto |].
    destruct (excluded_middle_informative (c = b)) as [He'|_]; [contradiction Hbc_neq; symmetry; auto |].
    destruct (excluded_middle_informative (c = e)) as [He'|_]; [contradiction Hce_neq; auto |].
    reflexivity. }
  apply (@n5_two_realizer_framework B R2 HR2 a b c d e
           Hab_neq Hac_neq Had_neq Hae_neq Hbc_neq Hbd_neq Hbe_neq
           Hcd_neq Hce_neq Hde_neq Hcovers rk1 rk2);
    try (rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e; lia);
    try (rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e; lia).
  - (* rk1 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxd Hyb] | [[Hxd Hyc] | [Hxe Hyc]]]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_b. lia.
    + subst x y. rewrite Hrk1_a, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_b, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_d, Hrk1_b. lia.
    + subst x y. rewrite Hrk1_d, Hrk1_c. lia.
    + subst x y. rewrite Hrk1_e, Hrk1_c. lia.
  - (* rk2 monotone on R2 *)
    intros x y HR. destruct (HR_only x y HR) as
      [Heq | [[Hxa Hyb] | [[Hxa Hyc] | [[Hxb Hyc] | [[Hxd Hyb] | [[Hxd Hyc] | [Hxe Hyc]]]]]]].
    + subst y. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_b. lia.
    + subst x y. rewrite Hrk2_a, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_b, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_d, Hrk2_b. lia.
    + subst x y. rewrite Hrk2_d, Hrk2_c. lia.
    + subst x y. rewrite Hrk2_e, Hrk2_c. lia.
  - (* L1 ∩ L2 ⊆ R2 — 25-cell enumeration *)
    intros x y HLa HLb.
    destruct (Hcovers x) as [Hx|[Hx|[Hx|[Hx|Hx]]]]; subst x;
    destruct (Hcovers y) as [Hy|[Hy|[Hy|[Hy|Hy]]]]; subst y;
      first [ apply HR2.(poset_refl)
            | exact HRab
            | exact HRac
            | exact HRbc
            | exact HRdb
            | exact HRdc
            | exact HRec
            | exfalso;
              rewrite ?Hrk1_a, ?Hrk1_b, ?Hrk1_c, ?Hrk1_d, ?Hrk1_e in HLa;
              rewrite ?Hrk2_a, ?Hrk2_b, ?Hrk2_c, ?Hrk2_d, ?Hrk2_e in HLb;
              lia ].
  - (* Distinguishing pair: (d, a) gives L1 d<a but L2 a<d. *)
    exists d, a. rewrite Hrk1_a, Hrk1_d, Hrk2_a, Hrk2_d. lia.
Qed.

